const updates = [{"id": "f2eecc9b-67f6-4f24-917c-8cd3e1407bca", "info": "Starting location: Home — Ballston, Arlington VA. Drive to first stop: ~49 min.", "log": "", "hist": ""}, {"id": "a804c187-16c8-4fc4-99fb-d0f3176aa8fd", "info": "Allow extra time — international Aer Lingus check-in can queue. Print or have confirmation 2JWMSW ready.", "log": "Washington Dulles International Airport\nAer Lingus terminal\nConf: 2JWMSW", "hist": ""}, {"id": "5a88f9f8-2289-4ecd-95e1-9bfa56ac3b26", "info": "Overnight transatlantic. Sleep as much as possible — Day 1 is a full drive and shoot day on arrival.", "log": "Flight: EI 116 · Aer Lingus\nDeparts: 17:15 IAD · Arrives: 05:15+1 DUB\nConf: 2JWMSW", "hist": ""}, {"id": "0a43de2d-819e-4fd6-ad2f-73ef19275d33", "info": "Starting location: Dublin Airport. Drive to first stop: ~5 min.", "log": "", "hist": ""}, {"id": "106bb66b-d693-4b92-893f-df5d2501d261", "info": "Immigration, baggage, Enterprise pickup. Target departure on N4 westbound by 7am.", "log": "Enterprise Car Rental · Dublin Airport\nConf: 73391556677627 · Jun 22–26 · $121.85 prepaid\nEnterprise desk in arrivals hall Terminal 1 — follow signs\n⚠️ Film protocol: request hand check + ETD swab at every security point\nKeep all film in carry-on — NEVER checked baggage\nClear ziplock bag labeled ''Film — Please Hand Check''\n🏧 ATM in arrivals Terminal 2 — Bank of Ireland or AIB · Get €150–200\n🛒 Stop at Centra/SuperValu in Boyle for water, snacks, day supplies\n⚠️ Load film holders: aircraft lavatory or changing bag in terminal\nTarget departure from airport: 7:00am", "hist": ""}, {"id": "97a0a5d2-9fb8-43ca-b8ad-5012d598be09", "info": "Island castle ruin (McDermott''s Castle) on Lough Key with three distinct shooting positions. Drive from Dublin Airport: 2h 25min · 168km via N4. Parking → lakeshore: 5 min walk. Parking → opposite bank viewpoint: 10–15 min walk. Parking → canopy walk high point: 20 min walk. Time on site: 60–75 min to hit all three positions.", "log": "✅ SIGNAL OK — near Boyle, good coverage\nLough Key Forest Park, Boyle, Co. Roscommon F52 Y732\nPhone: +353 71 967 3122\nParking: €6 · Admission (Rockingham Remembered Tour): €10\nTotal cost: ~€16 per person\nHours: 10:00am–5:00pm daily\nCall ahead re: early access · If gates closed, shoot from public jetty/roadside first\nRockingham Tour includes: Moylurg Viewing Tower + servant tunnels + Tree Canopy Walk\nBoat hire to Castle Island: €8/person · July/August only\n🥾 Waders for lakeshore position · Lough bottom is soft/muddy — move slowly\nAllow 90 min total", "hist": "Lough Key''s origin story begins with violence. In Irish mythology, Cé was the druid of the god Nuada. Wounded in battle, he fled south until he reached a flower-covered plain. When he died, a lake burst forth from his grave and flooded the plain — thus Loch Cé was born. The Mac Diarmada dynasty ruled from Castle Island for over five centuries. In 1184, a lightning strike killed between 110 and 140 people on the island, including the chieftain''s wife — one of the deadliest recorded events in medieval Ireland. The Annals of Loch Cé, compiled on this island, are now preserved in Trinity College Dublin.\n\nThe island''s great love story rivals Romeo and Juliet. Úna Bhán McDermott, the chieftain''s blonde-haired daughter, fell in love with Tomás Láidir Costello from a rival clan. Forbidden from marrying, Úna was confined on Castle Island and died of grief. Tomás swam to her grave every night until he contracted pneumonia and died. Legend says two trees grew from their graves and entwined together in an unbreakable lovers'' knot. Douglas Hyde, Ireland''s first president, immortalized the legend in Love Songs of Connacht (1893). The traditional lament \"Úna Bhán\" remains one of the great airs of Irish music.\n\nYeats visited around 1890 and planned to establish a mystical artistic order here — the plan never materialized. In the 1800s, architect John Nash — designer of Buckingham Palace and Regent''s Park — transformed the medieval ruin into a Gothic Revival folly for the King family, whose grand Rockingham House reportedly had 365 windows, one for each day of the year. That house burned in 1957. Underground tunnels built so servants could carry provisions unseen by the gentry still thread beneath the park. Recent archaeological excavations (2018–2023) by Professor Thomas Finan have unearthed silver pins, gaming pieces, and high-status 13th-century artifacts. The island also featured in Chris O''Dowd''s Emmy-winning sitcom Moone Boy (2012–2015).\n\nPop culture: The island featured prominently in Chris O''Dowd''s Emmy-winning sitcom Moone Boy (2012–2015), where it appears as the residence of the mysterious \"Island Joe.\" The Úna Bhán legend inspired the traditional song of the same name, one of the most recorded airs in the Irish repertoire — covered by everyone from Seán Ó Riada to The Chieftains. The area of Boyle also appeared in Stanley Kubrick''s Barry Lyndon (1975), which used numerous Irish locations for its 18th-century period drama."}, {"id": "ab0869eb-e95f-4390-afc8-d83cc6ed888c", "info": "Sruth in Aghaidh an Aird — Ireland''s tallest waterfall at ~50m, running up against the cliff face. Trailhead at Tormore off the Glencar road. 20 min walk to the falls.", "log": "📵 CHECK SIGNAL — remote area\nParking: small roadside layby at trailhead · Free\nWalk: ~20 min each way · Boots essential · Can be wet\nAllTrails: Sruth in Aghaidh an Aird and Devil''s Chimney", "hist": ""}, {"id": "7e076461-1c07-4f22-bb90-6322f2f77864", "info": "The most Clyde Butcher-esque subject of the Ireland leg. Mossy limestone grotto with a 15m single drop. Yeats referenced it in ''The Stolen Child''. Drive from Lough Key: 50min · 56km via N4 → N16 → R286. Parking → waterfall: 5 min flat paved walk.", "log": "⚠️ PATCHY — wooded gorge, unreliable. Download offline.\nLargandoon, Glencar, Co. Leitrim\nDrive from Lough Key: ~50min via N4 → N16 → R286\nParking: Free · Car park at entrance · teaSHED coffee shop on site\nParking → falls: 5 min flat paved path\nSwimming not permitted in plunge pool · Wading in stream below is fine\n🥾 Waders for stream position · ☂️ Tripod umbrella — gorge gets mist\nCan get crowded midday — arrive before 11:30am\nAllow 45–60 min · Depart ~12:30pm", "hist": "Glencar''s 15-metre cascade cuts through alternating layers of shale and Dartry Limestone laid down 330 million years ago, when Sligo sat near the equator beneath a warm tropical sea. The water is so rich in calcium carbonate it has built a growing tufa curtain across part of the rock face — an active geological process visible to the naked eye.\n\nBut Glencar''s immortality comes from a 21-year-old poet. In 1886, W.B. Yeats wrote \"The Stolen Child,\" placing us precisely here: \"Where the wandering water gushes / From the hills above Glen-Car.\" The poem''s fairies lure a child from the mortal world with perhaps the most haunting refrain in Irish literature: \"Come away, O human child! / To the waters and the wild / With a faery, hand in hand, / For the world''s more full of weeping than you can understand.\" The fairy changeling tradition Yeats drew on was lethally real — in 1895, Bridget Cleary of Tipperary was killed by her husband who believed she had been replaced by a changeling.\n\nMusical adaptations span generations: The Waterboys recorded \"The Stolen Child\" on Fisherman''s Blues (1988), Loreena McKennitt set it on her debut album, and it appears in Spielberg''s A.I. Artificial Intelligence (2001) and the animated film Song of the Sea (2014). Two kilometers away, the Devil''s Chimney (Sruth in Aghaidh an Aird) at 150 metres is Ireland''s tallest waterfall — and in southerly winds it appears to flow upward, water blowing skyward in a genuinely otherworldly spectacle. In 2020, drought conditions exposed a prehistoric knapping floor on the lakeshore — 930 pieces of chert potentially dating to 8,000 BC."}, {"id": "a45355da-327f-4909-b8de-c39433924588", "info": "17th century plantation castle on the shore of Lough Gill — tower house, round turret, full bawn wall, all reflected in the lake. OPW Heritage Card covers entry. Drive from Glencar: 25min · 18km south on R286 along the lakeshore. Parking → entrance gate: 3 min walk. Open Jun–Aug daily 10am–6pm.", "log": "✅ SIGNAL OK — Lough Gill area, reasonable coverage\nKilmore, Fivemilebourne, Co. Leitrim F91 FP71\nOPW Heritage Card accepted · Free parking on site\nOpen daily 10:00am–5:15pm\nShoot position: 54.264091, -8.334112 — save in Maps before departure\nWade from castle''s own south-facing shoreline near the Rose of Innisfree pier\n20–30ft out · Rocky lakebed — step carefully\nWaders essential\nEntry via castle grounds (OPW card covers admission)\nAllow 30–45 min · Depart 4:00 PM sharp", "hist": "This fortified manor is a physical palimpsest of conquest. The original tower house belonged to Brian na Múrtha O''Rourke, the last traditional Gaelic ruler of West Bréifne, described by the English Lord Deputy as \"the proudest man I had dealt with in Ireland.\" In September 1588, O''Rourke sheltered approximately 80 survivors of the Spanish Armada, including Captain Francisco de Cuéllar, who described O''Rourke''s wife as \"beautiful in the extreme.\"\n\nSheltering Spain''s sailors was treason. O''Rourke fled to Scotland and became the first person extradited within Britain on charges of crimes committed in Ireland. At trial in London, he refused to speak English, insisting on Irish. On 3 November 1591, he was hanged, drawn, and quartered at Tyburn. English planter Robert Parke then demolished O''Rourke''s tower house and recycled its stones to build his own manor — literally burying the Gaelic past beneath his courtyard cobbles. During 1970s–80s restoration, archaeologists discovered O''Rourke''s foundations beneath the stones, along with a sweat house (teach allais) — a uniquely Irish stone sauna. County Leitrim has over 100 recorded sweathouses, the highest density in Ireland.\n\nThe Isle of Innisfree is visible from the castle pier. Yeats wrote \"The Lake Isle of Innisfree\" — his most famous poem — after hearing a fountain tinkle in a London shop window, seized by sudden homesickness. He later grumbled about its popularity; it was once recited by thousands of Boy Scouts in his honor. Today it appears in Irish passports. The South Korean cosmetics brand Innisfree takes its name from the poem."}, {"id": "52e6bf4e-56a2-419d-ab31-a0766541692d", "info": "Rocky headland at the north end of Streedagh Beach with Classiebawn Castle and Benbulben visible to the southeast. Drive from Carrowmore direct: 30min · 25km via R292 → R291. Or via cabin: 15min to cabin + 35min to Streedagh. Parking → beach: 3 min walk. Parking → Streedagh Point headland: 15–20 min walk north along the beach.", "log": "⚠️ PATCHY — exposed headland, patchy. Download offline.\nStreedagh Point — western headland tip · NOT the beach, NOT Conor''s Island\nCoords: 54.4058, -8.5785 — save in Maps before departure\nDrive from Parke''s Castle: ~38 min\nParking: Free large car park at beach\nWalk: ~15 min WEST along beach to headland tip · then climb grassy high point\nNo entry fee · Tide: check tidetimes.ie Sligo Bay Jun 22\nLower tide = more foreground fossil rock exposed\nStrong westerly wind expected — wind protocol applies\nGolden hour: 9:00–9:48pm · Sunset: 9:48pm\nDrive home to cabin after: ~54 min", "hist": ""}, {"id": "8c46ffb6-3227-4948-9fff-46941b37a6b0", "info": "", "log": "✅ SIGNAL OK — cabin has WiFi\nInnisfreedom, Killerry, Ballintogher, Co. Sligo\nConf: 5869191106\nDrive from Streedagh Point: ~54 min\nCheck-in anytime · No formal check-in time\nEnd of Day 1 — crash for the night", "hist": ""}, {"id": "b157a051-7f6a-4fbf-a351-e407131f38b1", "info": "Starting location: Innisfreedom Cabin — Ballintogher, Sligo. Drive to first stop: ~86 min.", "log": "", "hist": ""}, {"id": "e37b2530-20c8-41d0-8375-7eddf77e0760", "info": "Slieve League Cliffs — 601m sea cliffs, among the highest in Europe. Upper car park puts you right at the Bunglass viewpoint — arrive before 8:30am to beat the coaches. Drive up through Teelin village following signs for Upper Car Park (not lower). Fill petrol in Donegal Town before turning west — nothing reliable on the R263 coastal approach.\n\nRoute order: Get all Bunglass shots first while the cliff is empty, then hike. Upper car park → Bunglass viewpoint (2 min). Pilgrim''s Path → cove overlook (10 min in). Shoulder approach (45 min). Upper shoulder (60 min). One Man''s Pass path shot (75 min). Return to car park (45–60 min back). Total: ~3.5 hrs.\n\nOne Man''s Pass: Narrow exposed ridge, drops 600m on both sides. Find wider sections to plant the tripod. Keep both tripod legs on the uphill side if there''s a slope. Don''t extend the tripod more than needed. Shoot in a wind lull — if it''s gusting hard, skip the ridge shot and move on.", "log": "📵 NO SIGNAL — remote Donegal cliffs. Satellite device active. Download offline.\nTeelin, Co. Donegal · Bunglass Upper Car Park\nDrive from cabin: ~2 hrs via N15 north → Donegal Town → R263 west to Teelin\n⛽ Fill petrol in Donegal Town — nothing reliable past there\nParking: €15/day upper car park · Arrive before 10am while still accessible\nDrive straight through the gate before the parking attendant arrives\nUpper car park → Bunglass viewpoint: 2 min walk\nUpper car park → cove overlook (Position 2): ~15 min hike\nUpper car park → shoulder (Position 3): ~45 min hike\nUpper car park → One Man''s Pass: ~90 min hike\nUpper car park → Slieve League SE Top: ~2 hrs hike\nReturn to car: ~60 min descending\nAllTrails: ''Slieve League Viewpoint through One Mans Pass'' · Saved offline · 4.7mi · 1,775ft · ~3h 13m\nDepart 2:00 PM → Assaranca Waterfall\nToilets at upper car park (seasonal) · No café until Carrick — bring food + 2L water\nCost: Free entry · €15 parking", "hist": "At 601 metres, Slieve League''s sea cliffs are nearly three times the height of the Cliffs of Moher (214m) and almost twice the Eiffel Tower. The name Sliabh Liag means \"mountain of the stone pillars,\" referring to the layered quartzite formations on the cliff face — Dalradian metamorphic rocks altered during the Caledonian orogeny 475–385 million years ago. Remarkably, these rocks can be directly correlated with rocks in Newfoundland — over 450 million years ago, parts of Ulster sat on the same tectonic plate as the Appalachian Mountains.\n\nOne Man''s Pass is a glacial arête — a knife-edge ridge approximately 400 metres long where the land drops precipitously on both sides. Naturalist Robert Lloyd Praeger described it in 1939 as \"one of the most remarkable walks to be found in Ireland — not actually dangerous, but needing a good head and careful progress on a stormy day.\" The northern precipice falls 1,500 feet into the corrie below.\n\nChristianity arrived here early. Saint Áed mac Bricc, a 6th-century bishop, lived as a hermit at the clifftop before his death in 589 AD. His chapel ruins survive among beehive huts, holy wells, and penitential cairns — evidence of over 1,000 years of documented pilgrimage. A Napoleonic-era signal tower (c.1804–1806) stands two-thirds up the mountain, one of 81 stations watching for a French invasion fleet. During WWII, large stone letters spelling \"ÉIRE\" were placed as navigation markers — Ireland remained neutral but quietly allowed Allied aircraft through the Donegal Corridor linking Lough Erne to the Atlantic. On 9 August 2020, Greg McEntee performed the first known BASE jump from the Eagle''s Nest section of the cliffs."}, {"id": "2b5f4717-201e-4724-a842-1ad264281a3e", "info": "Assaranca Waterfall — two-tier cascade dropping into a dark plunge pool, then draining straight to Maghera Beach and the Atlantic. The gorge is narrow with overhanging vegetation — shade likely even in the afternoon, which helps enormously for long exposures. Compact location: everything you need is within a 5-minute walk of the car park.\n\nThe vegetation in late June is all mid-green and collapses to the same Zone IV–V gray in B&W — don''t fight it. Let the rock faces go dark (Zone II–III) and let the white water do the work. Three distinct setups here, each meaningfully different.", "log": "⚠️ PATCHY — rural Donegal, unreliable. Download offline.\nFrom Slieve League Upper Car Park: ~45min, ~40km. Route: back through Teelin → Carrick → R263 west along the coast → R230 north toward Ardara → follow signs for Assaranca / Maghera. Small free car park right at the falls.\n\nCar park → base of falls: 3 min flat walk\nCar park → left bank elevated shelf: 5 min\nMaghera Beach: 2 min below the falls\nTotal time at location: 45–60 min\n\nLight: Arrives ~2:30pm. Sun will be west-southwest — potential backlight on the falls if clear sky. Use polarizer to cut glare on wet rocks (removes 1.5–2 stops). Overcast is better — eliminates dappled shadow/highlight problem in the gorge. Shade in the gorge likely regardless — meter carefully, may be 8–15 sec at f/22.\n\nFacilities: None. No entry fee. Free parking.", "hist": "The name Eas a'' Ranca essentially translates to \"waterfall\" — making \"Assaranca Waterfall\" technically tautological. This cascade flows off the slopes of Slievetooey Mountain through ancient metamorphic quartzites, tumbling into a deep dark pool. In local folklore, waterfalls were considered veils between realms — connected to the Tuatha Dé Danann, Ireland''s ancient mystical race, said to live beneath falling water. Stepping through at the right moment could transport you to Tír na nÓg, the land of eternal youth.\n\nOne kilometer further, the Maghera Caves harbor their own dark legend. Local oral tradition tells of people hiding in the caves from attackers — traditionally attributed to Cromwell, though historians note he never ventured this far north. More likely, the attackers were Vikings. A single male survivor allegedly fled deep into the cave system with his dog; the dog emerged 20 kilometers away in Glencolmcille, but the man was never seen again.\n\nNearby Ardara is a designated Heritage Town and home of the traditional Donegal Tweed weaving industry. Local musician John \"The Tae\" Gallagher (1923–2012) was described by broadcaster Ciaran Mathuna as \"probably the best fiddle player of all time.\" \n\nPop culture: Donegal is the birthplace of some of Ireland''s most globally recognized musicians. Enya (Eithne Pádraigín Ní Bhraonáin) was born in Gweedore, 30 miles north — her albums Watermark (1988) and Shepherd Moons (1991) sold over 70 million copies worldwide, her voice became the sonic shorthand for \"Celtic mysticism\" across film scores, commercials, and meditation playlists globally. Clannad — the family group that created the haunting theme for Robin of Sherwood (1984) and Harry''s Game (1982) — are also from Gweedore. Their sound effectively defined how the English-speaking world imagined ancient Ireland for a generation. Daniel O''Donnell, Ireland''s most beloved country singer, is from Kincasslagh just 15 miles from here."}, {"id": "3d0b6976-9981-4766-a00b-663cac9cb0ab", "info": "Glengesh Pass — a glacially carved valley with steep green walls dropping away on both sides of the ridge, the road snaking down in tight hairpin bends visible from the crest. The pass itself is the road — you''re shooting from pullouts, not hiking. Main viewpoint is a wide gravel shoulder on the south side as the road crests the ridge. The hairpin road is your compositional anchor — it''s what makes this shot unique and must stay in frame.\n\nThe green valley walls in late June are the technical challenge: without filtration they all compress to the same Zone IV–V gray and the image dies. A red filter is mandatory — it pushes the grass down to Zone III and separates lit vs. shadowed walls. Three positions here, each from a slightly different spot on the pass road.", "log": "📵 NO SIGNAL — remote mountain pass. Satellite device active. Download offline.\nFrom Assaranca Waterfall: ~20min, ~15km northeast via R230 → R261 through Ardara, then pass road climbs east. Main viewpoint pullout is obvious — wide gravel shoulder on the south side as the road crests the ridge.\n\nCar → viewpoint: 1 min (shooting from road shoulder)\nStep-down tree position (Shot 2): 5 min walk down from crest\nTotal time at location: 30–40 min\n\nLight: Arrives ~3:30pm. Sun west-southwest, sidelighting the valley walls — one wall lit, one in shadow, exactly the tonal asymmetry you want. Valley runs roughly north-south. Red filter critical regardless of sky conditions to separate green grass tones. Wind exposure on the ridge can be significant — bag on tripod hook.\n\nAfter Glengesh: ~1hr drive back to Innisfreedom cabin via Ardara → Donegal Town → N15 south → N16 → Ballintogher.\n\nFacilities: None. Free roadside parking.", "hist": "Gleann Géis — \"Glen of the Swans\" — is named for the whooper swans that historically wintered in this glaciated U-shaped valley, sitting approximately 900 feet above sea level between mountains reaching 1,400–1,700 feet. The road connecting isolated Glencolmcille to Ardara and the wider world is a famine road — one of the cruelest paradoxes of Ireland''s Great Famine (1845–1852).\n\nThe British government established road-building as the principal means of famine relief from September 1846, stipulating wages must be two pence less than the local rate and paid by the amount of work performed. Men, women, and children — already starving — were required to perform hard physical labor breaking through rocky terrain. Many died at the very worksites meant to save them. 1847, \"Black ''47,\" was the worst year. Ireland''s population fell from 8.2 million in 1841 to 6.55 million by 1851 — approximately one million dead from starvation and disease, over two million emigrated.\n\nAbandoned homesteads and stone-walled paddocks visible on the slopes are remnants of families who lived here before the famine. The nearby village of Port has been called \"the most remote and least visited corner of Ireland.\" American artist Rockwell Kent painted a portrait of Annie McGinley there in 1928, connecting this empty landscape to the wider Irish diaspora story.\n\nPop culture: Donegal''s remote landscapes have drawn filmmakers since the silent era. The 1935 Irish-language film Man of Aran director Robert Flaherty scouted these landscapes, while the broader Donegal landscape appeared in Hear My Song (1991) — the biographical film about Josef Locke, starring Adrian Dunbar — which won the BAFTA for Best British Film. The nearby area of Glencolmcille was used in The Closer You Get (2000), a gentle romantic comedy starring Ian Hart. Pete Postlethwaite filmed scenes for the ITV series In the Name of the Father in the broader Donegal area. Folk band Altan, widely regarded as one of Ireland''s greatest traditional music groups, are from the Donegal Gaeltacht and have made the region''s unique Donegal fiddle style internationally famous."}, {"id": "56a5d8e6-224c-4237-bee3-2c41a1069add", "info": "Starting location: Innisfreedom Cabin. Drive to Gleniff: ~41 min.", "log": "", "hist": ""}, {"id": "cafc2fb0-02b9-4d68-bb86-57e902184733", "info": "The Gleniff Horseshoe is a spectacular 10km loop road around the base of the Dartry Mountain cliffs. Drive clockwise from the Benwiskin Centre — the road circles under near-vertical quartzite cliff walls, through a remote valley with ruined mills, schoolhouses, and cave sites. This is a drive with frequent pull-over stops, not a hike. Allow 90 minutes.", "log": "📵 NO SIGNAL — deep valley, confirmed dead zone. Satellite device active. Download offline.\nStart: The Benwiskin Centre · Eircode F91 A389 · Free roadside parking\nPhone: +353 71 917 6721\nAllTrails: The Gleniff Horseshoe – Benwiskin Trail · 8.6mi · Moderate · ~3h 33m walk / 90 min drive with stops\nDrive clockwise from Benwiskin Centre\nSingle lane road — drive slowly · Watch for sheep and oncoming traffic\nSignage poor — use offline map for navigation\nFree throughout · No entry fees\nCoffee Kart at Benwiskin Centre on arrival and return\nAllow 90 min with stops and camera out", "hist": "The Gleniff valley sits beneath the Dartry Mountain plateau, the same carboniferous limestone formation as Benbulben. The Gleniff Barytes Mill (Stop 2) processed barium sulfate mined from the cliff face — barytes was used in paint and industrial processes, and the Dartry Mountains were one of Ireland''s main sources in the 19th and early 20th centuries. The schoolhouse ruins (Stop 5) date to the post-Famine era, built as part of the National School system in the 1850s-60s — evidence of a community that once farmed this remote valley. Diarmuid and Gráinne''s Cave (visible high in the cliff above the schoolhouse) is one of dozens of caves across Ireland associated with the legend of the star-crossed lovers from the Fenian Cycle. Magic Hill (Stop 3) is a well-known optical illusion caused by the horizon line created by the surrounding cliff walls — the road is actually slightly downhill but appears to slope upward."}, {"id": "adb12af6-722e-4b70-bc48-271dc0afc71b", "info": "Benbulben Forest Walk — Ireland''s most distinctive mountain, a flat-topped limestone plateau with sheer serrated cliff faces. Three completely different shots here depending on how far you go. The geometry of that cliff edge against the sky is the defining element — nothing else in Ireland looks like this.\n\nShoot the approach road silhouette BEFORE you even park — pull off on the way in. Then the southwest meadow for the close pinnacle shot. Then hike 45 min if legs allow after yesterday''s One Man''s Pass. The hike is optional — Positions 1 and 2 from the road and meadow are both strong images without it.", "log": "⚠️ PATCHY — forested hillside, unreliable. Download offline.\nGortarowey Forest Recreation Area · Free parking · Free entry\nAllTrails: Benbulben Forest Walk · 3.5 mi · Easy · ~1.5 hrs walk · Allow 3 hrs with camera\nStart at upper car park · Walk clockwise for best approach\nNo toilets at car park or on trail — sort before you arrive\nNo bins on trail — pack out all rubbish\nCan be windy on exposed sections · Gravel path throughout\nTrail passes through Coillte forestry — may have tree felling activity", "hist": "Benbulben''s flat-topped profile was carved when glaciers cut into Carboniferous limestone, the harder Dartry Limestone on top resisting erosion while softer shale below was sculpted away. The cliff faces harbor Fringed Sandwort (Arenaria ciliata) — an arctic-alpine Ice Age relict found nowhere else in Ireland, with genetic affinity to Arctic rather than European populations.\n\nThe mountain''s greatest story is Diarmuid''s death. Years after the lovers'' flight, Fionn organized a boar hunt on Benbulben''s slopes, knowing an enchanted boar was prophesied to kill Diarmuid. The boar fatally gored him. Fionn possessed the power to heal anyone with water cupped in his magical hands — but three times he went to a stream and three times let the water trickle through his fingers, consumed by jealousy over Gráinne. Only when his grandson threatened to kill him did Fionn relent — but Diarmuid was already dead. The tale predates the 10th century and is believed to be the basis for the Arthurian legend of Tristan and Iseult. County Sligo''s coat of arms bears a boar''s head referencing this myth.\n\nDuring the 1922 Irish Civil War, six anti-Treaty IRA fighters — including elected TD Seamus Devins — were hunted down and killed on Benbulben''s slopes, allegedly after they had surrendered. They are remembered as \"The Noble Six.\" \n\nPop culture: Benbulben''s silhouette is the visual centerpiece of Song of the Sea (2014), the Academy Award-nominated animated film by Cartoon Saloon that drew directly on Yeats''s mythology and Sligo''s landscape. The studio confirmed Benbulben as a primary visual reference for the children''s lighthouse home. The Pogues referenced the broader Fionn Mac Cumhaill mythology in \"The Sickbed of Cuchulainn\" from Rum, Sodomy, and the Lash (1985). Yeats''s poem \"Under Ben Bulben\" — which uses the mountain''s name in its title — has been quoted in literary eulogies and graduation speeches globally for 80 years and appears in the Netflix documentary The Irish Pub (2023). The mountain''s distinctive profile has been used in Irish tourism campaigns since the 1970s and is one of the most reproduced landscape images in Irish art."}, {"id": "01e86cb4-fc4f-41db-8c38-931c56feb3ba", "info": "Mullaghmore Head is one of Ireland''s most layered photography locations — the classic 300mm compression shot of Classiebawn Castle with Benbulben looming behind it, dramatic surge rock shelves along the headland loop, a secret sea cave accessible only at low tide, and some of the Atlantic''s most powerful swells in Europe. Park at the harbour and drive or walk the R279 loop clockwise. Two visits planned: Day 1 (afternoon light) and Day 3 (afternoon scout + golden hour). ⚠️ Check tide tables before both visits — cave access requires low tide.", "log": "✅ SIGNAL OK — coastal village, good coverage\nPark: Mullaghmore Harbour · Free\nDrive the R279 loop clockwise · 2.8mi · ~1 hr walk or 15 min drive with pull-overs\nAllTrails: Mullaghmore Head Loop · Easy · 2.8mi · ~1 hr\nFree throughout · No entry fees\nPub + café in Mullaghmore village\n\n⚠️ SECRET CAVE: Low tide access only — check Irish tide tables for Jun 22 + Jun 24\nTide resource: www.tideschart.com/Ireland/Mullaghmore\nCave is on the northwest headland side of the loop · Look for the rock arch at water level\n\nDay 1 visit (~4:45 PM): Southwest light · Surge channel shots · Cave if tide allows\nDay 3 visit (2 PM–sunset): Scout at 2 PM · Castle + Benbulben compression as light drops · Golden hour 8:30–10 PM at southwest headland for lit castle shot · Sunset Jun 24: 10:05 PM", "hist": "Classiebawn Castle was commissioned by the 3rd Viscount Palmerston — twice British Prime Minister — and completed in 1874. The castle eventually passed to Lord Louis Mountbatten — Admiral of the Fleet, last Viceroy of India, Supreme Allied Commander Southeast Asia, great-grandson of Queen Victoria, mentor to Prince Charles.\n\nOn the morning of 27 August 1979, Mountbatten boarded his 29-foot cabin cruiser Shadow V with six family members. At 11:15 AM, a 50-pound gelignite bomb planted by IRA operative Thomas McMahon was detonated by remote control from shore. Mountbatten, his 14-year-old grandson Nicholas Knatchbull, 15-year-old local boat boy Paul Maxwell, and 83-year-old Dowager Lady Brabourne were killed. McMahon had been arrested at a routine checkpoint 80 miles away — two hours before the bomb detonated. That same afternoon, the IRA''s Warrenpoint Ambush killed 18 British soldiers — the deadliest single attack on the British Army during the Troubles. The events were dramatized in Season 4 of Netflix''s The Crown (2020).\n\nIronically, Mountbatten supported Irish unity. Former MI6 chief Maurice Oldfield had personally warned him not to travel to Ireland in 1979. Mountbatten replied: \"But the Irish are my friends.\" Oldfield responded: \"Not all of them.\"\n\nMullaghmore Head is now ranked among the top ten big-wave surfing spots in the world. In 2020, surfer Conor Maguire rode an estimated 60-foot wave here, described as \"cold as Mavericks, a lip like Teahupoo.\""}, {"id": "4a716c4d-debd-463e-af50-fecd0c08b0fc", "info": "Starting location: Innisfreedom Cabin. Drive to Downpatrick Head: ~90 min via N59 through Ballina.", "log": "", "hist": ""}, {"id": "c699be8e-ed51-4b51-80bb-71ef5754c2bc", "info": "Downpatrick Head + Dún Briste — 45m isolated sea stack, 80m offshore, separated from the mainland in a storm in 1393. The layered limestone bedding — 25 million years of strata — is visible in every shot. The WW2 lookout post on the mainland cliff adds human scale and historical context. Unfenced cliff edge throughout — treat it with respect, especially with wind.\n\nSea cave access — read carefully: The cave shots (Imgs 5 & 7) require descending a series of slippery ledges from near the car park around the base of the headland. North Mayo Tourism explicitly states they do not encourage this and advise hiring a local guide. The rocks are covered in sea life and extremely slippery. Only attempt at very low tide, calm sea, and with a second person present. A local guide from Ballycastle is strongly recommended — ask at the village before committing. If conditions are not right, skip the cave and the cliff top shots are still exceptional.\n\nBlowhole (Poll na Seantainne): 150m inland from the cliff edge, a huge underground cave links it to the sea. Fenced viewing platform. When swell is running, spray shoots up from the chimney — worth checking on arrival.", "log": "📵 NO SIGNAL — remote Mayo headland. Satellite device active. Download offline maps.\nFree entry · Free parking (large car park, recently extended)\n⚠️ Do not leave valuables visible in car — break-ins reported\nWalk: 500m / 10 min from car park to stack viewpoint · Grass path, can be very muddy\nAllTrails: Downpatrick Head · 1.4km · Easy · ~20 min\nCoffee kiosk ''Tea by the Sea'' at car park\n⚠️ NO fence at cliff edge — unguarded 40m drop · Watch bubble grass underfoot\n⚠️ No visit in wind warning conditions\n\nCAVE ACCESS — LOW TIDE ONLY:\nLedges start near car park and traverse around base of cliffs to cave entrance\nCave faces north directly onto Dún Briste · Midsummer light floods in evenings\n⚠️ Extremely slippery — sea life on rocks · Risk of tide trapping + rogue waves\n⚠️ Do not attempt without checking tide tables + local advice first\nTide resource: www.tideschart.com/Ireland/Ballycastle-Mayo\n\nLOCAL CONTACTS FOR CAVE CONDITIONS:\nMick Hunt (local photographer, documented cave access):\n  Email: mhd@live.ie\n  Instagram: @mickh51\n  Website: www.mhphotography.ie\n\nGareth McCormack (professional landscape photographer, shot from cave Jul 11):\n  Website contact form: www.garethmccormack.com\n  Instagram: @garethmccormack\n  Based in Enniscrone, Co. Sligo — local to the area\n\nGareth''s article on the cave shot: garethmccormack.com/midsummer-magic-at-downpatrick-head\nMick Hunt''s Flickr + blog post: flickr.com/photos/mickhuntphotography/43790671741", "hist": "The 45-metre sea stack Dún Briste was separated from the mainland during a massive overnight Atlantic storm in 1393. A passage in the journal of MacFirbis describes \"the cutting off of the rock of Duross promontory by the sea.\" People were stranded atop the newly created island and had to be rescued using ship''s ropes. In 1981, a helicopter expedition discovered remains of two medieval buildings, field walls, cultivation ridges, and a corn-grinding quern still sitting on the grassy summit — a frozen snapshot of the community that lived there when the land fell away.\n\nThe headland''s patron saint legend tells of a confrontation between St. Patrick and the tyrannical pagan chieftain Crom Dubh. When Crom Dubh refused to convert, Patrick struck the ground with his crozier, splitting the headland and casting Crom Dubh and his fort into the sea — creating Dún Briste. The spectacular blowhole Poll na Seantainne (\"Hole of the Old Fire\") connects to the sea via an enormous underground cave; on stormy days, spray shoots skyward like smoke, giving the feature its name. During the 1798 Rebellion, 25 men — Irish and French soldiers — took refuge on a ledge inside the blowhole. The tide came in before ladders could be replaced, and all 25 drowned.\n\nA WWII lookout post (LOP 64) survives on the headland, alongside the stone \"ÉIRE 64\" marker — one of 83 placed around Ireland''s coastline to signal neutral territory to passing aircraft. In August 2016, Scottish climber Iain Miller successfully climbed the sea stack after four failed attempts, reaching the summit on the anniversary of the Mountbatten assassination.\n\nPop culture: County Mayo — the county containing Downpatrick Head — is experiencing a cultural moment. Martin McDonagh''s The Banshees of Inisherin (2022), filmed on Achill Island 30 miles south, won the BAFTA for Best Film, earned six Academy Award nominations, and put the West of Ireland landscape before a global audience. The stark Mayo coastline has been described as \"the landscape that made the film.\" Liam Neeson, who starred in Rob Roy (1995) filmed partially in Glencoe, has spoken extensively about the influence of the Irish west coast on his sensibility as an actor. Louis Marcus''s 1959 documentary Fleadh Cheoil filmed traditional music gatherings in Mayo; the county''s music tradition fed directly into the folk revival. The area''s prehistory inspired Heinrich Böll''s Irish Journal (1957), which helped spark German tourism to the west of Ireland and remains in print in 18 languages."}, {"id": "2a0c8213-db15-4221-b174-1626e719dc06", "info": "Aughris Head is a rugged, largely undiscovered headland on the south shore of Sligo Bay. The clifftop loop walk passes a WWII lookout post, a cliff-edge Iron Age promontory fort, a holy well associated with St. Patrick, and the ruins of a deserted village. Views across Sligo Bay to Benbulben and Knocknarea are exceptional. Park at the Beach Bar — a traditional Irish pub at the trailhead.", "log": "⚠️ PATCHY SIGNAL — rural Sligo coast, unreliable. Download offline maps.\n⚠️ OPTIONAL STOP — after a 3hr session at Downpatrick, take this if energy allows\nAfter Aughris: ~25 min back to cabin. If time/energy remains, reshoot window available\nfor Streedagh, Glencar, Mullaghmore, or Devil''s Chimney before heading home.\n\nPark: Beach Bar car park · Free · Aughris, Co. Sligo\nAllTrails: Sligo Bay Circular · 2.2 mi · Easy · ~47 min · 4.8 stars\nTrail refs: sligowalks.ie/walks/aughris · aughris.com/the-walk\nAllow 2 hours with camera stops\n⚠️ Road to Aughris is narrow — not suitable for coaches or campervans\n⚠️ Path can be muddy and slippery after rain — sturdy footwear essential\n⚠️ Some unfenced cliff sections — take care\n⚠️ Start of walk not well signposted — follow Wild Atlantic Way signs south from Sligo,\nturn at Aughris Head sign, continue 200-300m past the Beach Bar junction,\npark at sharp bend on left before cul-de-sac · Trail starts between house garden and pier\nNo dogs allowed on cliff path section (crosses farmland)\nBeach Bar pub on site — food, soup, toasties, Guinness · Check opening hours in advance\nOn a clear day: views to Benbulben, Knocknarea, and as far as Slieve League in Donegal", "hist": "Aughris Head has been inhabited since prehistoric times — the promontory fort dates to the Iron Age, likely 500 BC to 400 AD, built defensively on the cliff edge above the Atlantic. The holy well on the headland is one of dozens across Sligo associated with St. Patrick''s 5th-century mission. The deserted village at the heart of the headland was abandoned during or after the Great Famine (1845–52), when the rural Mayo and Sligo coastline lost enormous proportions of its population to death and emigration. During World War II, Ireland''s neutrality required coastal monitoring — the lookout post here was one of over 80 Emergency Observation Posts built along the west coast between 1939 and 1942, manned by the Local Security Force."}, {"id": "42a60a60-496f-40f4-85b5-8a81674d7adc", "info": "Starting location: Innisfreedom Cabin — Ballintogher, Sligo. Drive to first stop: ~41 min.", "log": "", "hist": ""}, {"id": "f9686c68-0700-4412-a5c1-0d3cba89ee9c", "info": "Only if conditions are spectacular. Glencar 25 min from cabin; roadside Benbulben 20 min.", "log": "", "hist": ""}, {"id": "d07ae6e8-e61d-47c9-af76-b437684c292c", "info": "Load all gear. Return key per cabin instructions. Check-out by 11am.", "log": "✅ SIGNAL OK — cabin has WiFi\nInnisfreedom, Killerry, Ballintogher · Conf: 5869191106", "hist": ""}, {"id": "94f282a4-4886-4ece-96c9-454b60f3268b", "info": "Straight shot. Drop Enterprise at Dublin Airport arrivals first, then Airlink bus or taxi to Moxy.", "log": "Enterprise return: Dublin Airport Terminal 1 · Conf: 73391556677627\nAirlink 747 bus: Airport → city centre ~30 min / €8", "hist": ""}, {"id": "39c9f362-a5ec-44c4-8474-488f3192293f", "info": "James and Dad arriving. First afternoon in Dublin — easy wander, pubs, food. Plan tomorrow over dinner.", "log": "Moxy Dublin City\nPhil Conf: 99210319 · James Conf: 99222693\nJun 26–28 · 2 nights · 2 rooms (Twin each)", "hist": ""}, {"id": "cce3775e-779f-41cb-8e94-f24100750b54", "info": "Starting location: Moxy Dublin City. Drive to first stop: ~8 min.", "log": "", "hist": ""}, {"id": "07d4c46f-b141-4b45-bbb7-751b61d589a2", "info": "Self-guided walk through the south Dublin filming locations. All within 20 min walk of each other.", "log": "✅ SIGNAL OK — Dublin city centre\nStart: Synge Street CBS, Dublin 8\nAll within 20 min walk in Liberties/south Dublin", "hist": ""}, {"id": "1f59221c-97b7-4916-b944-00d4ee1aecf4", "info": "Book in advance — sells out, especially weekends. 7 floors of exhibition. Gravity Bar at the top: 360° view of Dublin over your complimentary pint.", "log": "✅ SIGNAL OK — Dublin city centre\nSt James''s Gate, Dublin 8\nBook: guinness-storehouse.com", "hist": ""}, {"id": "beaca1b9-1504-4efd-87e9-e7ebe22fb2c2", "info": "Named after Thomas ''Bang Bang'' Dudley, a famous Dublin character. 28 craft beer taps, proper pub food.", "log": "48 Thomas St, The Liberties, Dublin D08 Y44A", "hist": ""}, {"id": "8926f072-ca1a-42e1-a44e-344bffc5a041", "info": "The original Dublin distillery in Smithfield — 15 min walk from Guinness. Book in advance. Interactive tour with whiskey tasting.", "log": "✅ SIGNAL OK — Dublin city centre\nBow St, Smithfield, Dublin 7\nBook: jamesonwhiskey.com", "hist": ""}, {"id": "a975524a-8ce9-4bc9-8beb-b0e3e301d70c", "info": "DART southbound from city center. Alight at Dalkey station, 10 min walk to Coliemore Harbour. WhatsApp Ken the Ferryman before heading down.", "log": "✅ SIGNAL OK — Dublin suburb\nDART: Tara St or Pearse → Dalkey (~35 min) · ~€4 return\nKen the Ferryman: WhatsApp +353 85 242 6516\nRuns: Apr–Sep · 10am–6pm · weather permitting\nFerry: €10/person return · Walk-up, no booking needed", "hist": ""}, {"id": "e40f04c8-f0e4-4df2-92cc-ad64e6d8cd05", "info": "The final scene of Sing Street was filmed here — Conor and Raphina''s dawn escape. St Begnet''s 7th century church ruins, Martello tower, feral goats, grey seals, puffins.", "log": "✅ SIGNAL OK — Dublin city centre\nKen the Ferryman: +353 85 242 6516 (WhatsApp first)\nFerry: €10/person return · 10 min crossing\nWave from jetty to call boat back", "hist": ""}, {"id": "831036f4-fc12-4703-a6c2-1871d3b7124d", "info": "Back by DART. Whelan''s on Wexford Street for legendary live music. ⚠️ EI 3226 departs 11:30am tomorrow — leave Moxy by 9:30am.", "log": "Whelan''s: 25 Wexford Street, Dublin\n⚠️ Tomorrow: EI 3226 DUB→GLA 11:30am · Conf: 2FH8WF\nLeave Moxy by 9:30am", "hist": ""}, {"id": "16f65dee-687f-47a0-92f9-88455e9d8507", "info": "Starting location: Moxy Dublin City. Drive to first stop: ~5 min.", "log": "", "hist": ""}, {"id": "7b58e349-4ddb-4667-87fe-cf9e3f257bac", "info": "Check out by 9:30am. Taxi or Airlink bus to Dublin Airport. Allow 45–60 min.", "log": "Moxy Dublin City · Conf: 99210319\nAirlink Bus 747: city centre → DUB ~30 min / €8", "hist": ""}, {"id": "ea16ca4a-09d8-4f73-a92f-fe4315935f9f", "info": "Short hop. Aer Lingus Regional operated by Emerald Airlines. Land Glasgow 12:50pm.", "log": "Flight: EI 3226 · Emerald Airlines\nDeparts: 11:30 DUB · Arrives: 12:50 GLA\nConf: 2FH8WF\n⚠️ Leave Moxy by 9:30am", "hist": ""}, {"id": "9ceace35-57c6-4782-9e52-d8457eedb81a", "info": "Scotland rental car booked by James. Fill up fuel immediately — then take A82 south briefly, join A828 west coast route toward Appin and Castle Stalker. Quieter, more scenic, avoids motorway.", "log": "Scotland rental car: booked by James Shaheen\nFuel: Fill up at Glasgow before heading north\nRoute: A82 → A828 west coast via Appin → Ballachulish → Glencoe\n⚠️ A828 adds ~45min vs direct A82 but passes Castle Stalker", "hist": ""}, {"id": "ef1d233a-d0ba-428f-8715-c21eca069aaa", "info": "14th century tower house on a tidal islet in Loch Laich, an inlet off Loch Linnhe. Mountains of Morvern rise directly behind across the water. One of the most isolated and perfectly composed castle subjects in Scotland — the keep rises straight from the water with no land visible at mid-to-high tide. Afternoon sun hits the west face directly at this hour.", "log": "⚠️ PATCHY — rural Argyll, limited. Download offline.\nCastle Stalker View Café car park — free, open access\nShore access: short track down from café\nCoords: 56.5544°N, 5.4806°W · near Appin village\nTide: check tidetimes.ie for Jun 28 Loch Laich before departure\nAllow 45–60 min · No permit required\nDistance from GLA: ~1hr 45min via A828", "hist": "Caisteal an Stalcaire — \"Castle of the Hunter\" — has walls up to 2.7 metres thick rising four storeys from the rock. The name derives from King James IV''s passion for falconry; he used the castle as a hunting lodge during frequent Highland visits, and the worn coat of arms above the door may be the Royal Arms placed during his patronage. James IV is believed to have visited frequently around 1490–1513.\n\nThe castle''s most notorious episode: around 1620, Duncan Stewart, 7th Chief of Appin, lost it to the Campbells of Airds in a drunken wager — a castle traded for an eight-oared rowing boat. Local legend adds a supernatural dimension: a witch had cursed the Stewarts, predicting they would lose the castle \"by water.\" The Stewarts attempted recapture multiple times. During the 1745 Jacobite Rising, they besieged the Campbell-held castle, but their 2-pound cannonballs merely bounced off the thick medieval walls.\n\nThe castle''s most famous appearance is as \"The Castle of Aaaargh\" in Monty Python and the Holy Grail (1975) — the castle where the Holy Grail supposedly resides. It also appears in Highlander: Endgame (2000). The castle fell to ruin after 1840 and its roof was possibly removed to avoid the roof tax. In 1965, Lt. Col. D.R. Stewart Allward began a decade-long restoration — doing the work himself with family and friends. His family still owns the castle and personally conducts limited summer tours for approximately 12 visitors per day."}, {"id": "32597a5a-70fb-4870-b783-fc8b042746f5", "info": "A beautiful waterfall on the River Coe tucked just inside the western entrance to the Glencoe valley. First photographic stop of the evening — quieter than the main valley pulloffs further east. Best after rain when the flow is strong.", "log": "Ballachulish PH49 4HX · Roadside access\nWear waterproof footwear — muddy and slippery\nAllow 15 min", "hist": ""}, {"id": "d30e5ef1-7729-45c8-af4c-2edaadda73f6", "info": "First dramatic viewpoint entering Glencoe from Ballachulish — the three great spurs of Beinn Fhada, Gearr Aonach, and Aonach Dubh rising directly from the valley floor. Classic pull-off with large car park. Quick stop on arrival — light will be evening warm here.", "log": "A82, Ballachulish PH49 4HX\nFree parking · Large car park\nAllow 30 min", "hist": ""}, {"id": "f9734280-96b1-4059-892a-50cc77d95eaf", "info": "Three separate streams converging in a single dramatic cascade right beside the A82. One of the most accessible and photogenic stops in Glencoe — water comes together between the flanks of the Three Sisters above. Rocky gorge and fast-moving water make it a natural 4x5 subject.", "log": "A82, Ballachulish PH50 4SQ\nPark on road · Free · Walk back ~20m · Climb down under bridge for close access\nAllow 15 min", "hist": ""}, {"id": "5437f96a-83ad-414b-9387-0c26c3f4c286", "info": "Classic elevated view over Loch Achtriochtan and the Three Sisters of Glencoe. Scout your positions here for tomorrow''s full day — note light direction, foreground options, and tripod placements. Good warm-up stop before River Coupall.", "log": "A82, Ballachulish PH50 4SF\nFree parking · Open 24 hours\nAllow 1 hour", "hist": ""}, {"id": "faa3698d-ed3e-4df9-a7d4-f60ce0fd6f95", "info": "The defining image of the Scottish Highlands. A near-perfect volcanic pyramid rising 1022m directly from the flat moor with no foothills. River Coupall flows across the moor in front, boulders mid-stream, open sky above. Tonight: scout your exact sunrise position first — tripod placement, reflection pool, boulder cluster — then shoot as light warms toward golden hour. The west face lights orange-red in the last hour before sunset.\n\n⚠️ Lagangarbh Hut (Wee White House) — the iconic white cottage at the foot of Buachaille Etive Mòr is a 5 min walk from the Altnafeadh layby, just across the footbridge over the River Coupall. Don''t miss it — it''s one of the most photographed buildings in Scotland and you''re already here.", "log": "⚠️ PATCHY — Glencoe approach, unreliable. Download offline.\nPark: A82 layby at River Coupall bridge\nCoords: 56.6537°N, 4.9418°W\nWading required: knee-high wellies essential, camera in river for Shots 2+3\nMidges in evening calm — bring repellent\nClachaig Inn: 10min from layby", "hist": "The Great Herdsman of Etive is probably the most photographed mountain in Scotland. Its pyramidal summit — Stob Dearg at 1,021 metres — is part of the Glencoe Caldera, an ancient supervolcano that erupted approximately 420 million years ago. Glencoe was the first place in the world where caldera collapse was recognized in ancient volcanic rocks — pioneered by geologists Clough, Maufe, and Bailey in their landmark 1909 paper. The rock is primarily rhyolite — the same type found at Yellowstone''s supervolcano. During peak glaciation 20,000 years ago, Rannoch Moor was buried under approximately one kilometer of ice.\n\nThe mountain has a sobering casualty record — up to 13 deaths in a single year. The Curved Ridge, first ascended in April 1898, is one of Scotland''s most famous scrambling routes. Climber Dougal Haston — who later summited Everest in 1975 before dying in an avalanche at 36 — reportedly redecorated the interior of nearby Lagangarbh Hut in the style of Jackson Pollock, enraging the Scottish Mountaineering Club authorities.\n\nThe Glen Etive road became \"The Skyfall Road\" after Bond (Daniel Craig) and M (Judi Dench) drove the Aston Martin DB5 through it in Skyfall (2012). The connection runs deeper than fiction: Ian Fleming''s family actually owned the Dalness Estate in Glen Etive. In You Only Live Twice, Fleming gave Bond a Scots backstory with his father hailing from Glencoe."}, {"id": "a8ea0761-f5da-4362-b973-72cce0c8c4ab", "info": "The waterfall featured in the James Bond film Skyfall (2012) driving sequence down the Glen Etive road. Dramatic multi-tiered falls with Buachaille Etive Mòr visible in the background. One of the finest waterfall photography locations in the Highlands — remote, uncrowded, and exceptional.", "log": "Glen Etive Road, Ballachulish PH49 4JA\nFree parking nearby\nAllow 30 min\n⚠️ Single track road — allow time for passing", "hist": ""}, {"id": "b890a0ff-d076-43ea-84ce-1a4c3b276f88", "info": "Historic climbers'' inn deep in the Glencoe valley. 10 minutes from the River Coupall layby. Call ahead to confirm late arrival. Request packed breakfast bag tonight — you need to leave by 4:10am tomorrow morning.", "log": "✅ SIGNAL OK — Clachaig Inn has WiFi\nClachaig Inn, Glencoe PH49 4HX\nConf: 6870559172 · Ref: #BB26031220300319\nPhone: +44 1855 811252\nJun 28–30 · 2 nights · 2 rooms (Twin + Double, B&B) · £780", "hist": ""}, {"id": "a03aff39-38fa-4ac0-83be-a15bbe9932a1", "info": "Starting location: Clachaig Inn — Glencoe PH49 4HX. Drive to first stop: ~5 min.", "log": "", "hist": ""}, {"id": "85cb3ff9-a32b-4d41-b525-01c37e090c4e", "info": "The hidden valley of Coire Gabhail — where the MacDonalds hid their rustled cattle, and where survivors of the 1692 Massacre took refuge. Completely invisible from the road. The approach descends into the River Coe gorge, crosses via metal staircase and wooden bridge, then climbs steeply through boulders and rock slabs. The valley floor opens suddenly — a flat hidden plain ringed by the Three Sisters, waterfalls dropping from the walls, enormous boulders deposited by ancient landslide.", "log": "📵 NO SIGNAL — deep Glencoe glen. Satellite device active. Download offline.\nPark: Three Sisters Car Park, A82 · Free · Arrive by 7:15am — fills fast in summer\nCoords: 56.6679°N, 4.9863°W\nDistance: 4km out and back · 375m elevation gain · 2–2.5hrs\nScrambling + river crossing — proper boots essential · trekking poles useful\n🦟 Midges in sheltered valley — repellent accessible, not buried in pack", "hist": "Coire Gabhail — \"Corrie of the Bounty\" — is a hanging valley concealed behind a massive ancient landslip, invisible from the glen below. The MacDonalds hid stolen cattle here from rival clans — particularly the Campbells — for generations. On the night of 13 February 1692, it became a refuge for survivors of the worst act of treachery in Highland history.\n\nThe political background: after William of Orange deposed the Catholic King James VII in 1688, all Highland chiefs were required to swear allegiance by 1 January 1692. Chief Alasdair MacIain arrived at Fort William on 30 December but was told he must travel to Inveraray — 60 miles through a winter storm. He arrived and swore on 6 January, six days late. John Dalrymple, Lord Stair, seized the opportunity — his letters reveal the decision predated the deadline: \"the clan Donell must be rooted out.\" On 1 February, 120 soldiers under Captain Robert Campbell of Glenlyon arrived requesting \"free quarter.\" Campbell''s own niece was married to one of MacIain''s sons. For twelve days, soldiers ate, drank, and played cards with their hosts. Only 13 of the 120 were actually Campbells.\n\nAt 5:00 AM on 13 February, the killing began simultaneously in three settlements. MacIain was shot rising from bed. His wife had her rings bitten from her fingers. Thirty-eight MacDonalds were killed; approximately forty more died of exposure fleeing into a blizzard. Those who reached the Lost Valley survived. In August 2023, archaeology student Lucy Ankers discovered a hoard of 36 coins buried under a hearthstone in MacIain''s Summerhouse — silver coins of Louis XIV, Elizabeth I, and Charles I, none minted after the 1680s. The owner never returned for them. George R.R. Martin explicitly cited the Glencoe Massacre as a primary inspiration for the Red Wedding in Game of Thrones."}, {"id": "27fd4372-e2ea-4e1c-ad72-a8e10cc448ad", "info": "Turn south on Glen Etive road at the A82 junction — same junction as the Skyfall car chase. Drive 1 mile in, park left after a small dip. The waterfall drops directly in front of you with Buachaille Etive Mòr''s south face rising behind it. Completely different angle on the Buachaille from the River Coupall shots — looking up from the south rather than the east. The pyramid reads more muscular from here. The waterfall provides a foreground element the River Coupall position doesn''t have.", "log": "⚠️ PATCHY — Glencoe approach, unreliable. Download offline.\nTurn south on Glen Etive road at A82 junction (signed)\nDrive 1 mile — park left after small dip in road · informal layby\n1 minute walk to falls · Free · No permit\nAllow 45 minutes\nOvercast actively helps — more cloud = longer exposure = more water silk", "hist": "The River Etive flows peat-dark from Rannoch Moor, its amber color from decomposed vegetation accumulated over thousands of years. The glen''s mythology predates the Fianna legends. In the Ulster Cycle, Deirdre and Naoise — Ireland''s great tragic lovers — fled King Conchobhar''s court and settled here. Deirdre''s lament is preserved in the Glen Massan Manuscript (c.1238): \"Glen Etive, O Glen Etive / There I raised my earliest house / Beautiful its woods on rising / When the sun fell on Glen Etive.\" Place names still preserve the legend: Dun MhicUisneachan, Coille Naoise, and \"Deirdre''s Drawing Room.\"\n\nScottish folklore assigns the glen its own monster: the Fachan (Direach Ghlinn Eitidh), described as having a single eye, a single hand protruding from its chest, and a single leg. The film location list is extraordinary: Harry Potter and the Deathly Hallows (lakeside camping scenes and dragon escape into Loch Etive), Braveheart, Thor: The Dark World, and Skyfall.\n\nThe glen has suffered from its Skyfall fame. Irresponsible car camping after the 2012 release turned sections into what Highland Councillor Andrew Baxter called \"Glen Midden.\" The Etive Mòr Waterfall viewpoint''s pristine heather has been trampled by photographer footfall into \"a waterlogged, churned-up wasteland\" — a cautionary tale for any visit here."}, {"id": "880057cb-aec0-4576-8902-7c638f227f23", "info": "Small but photogenic waterfall just off the Glen Etive road. Quick stop on the way to Skyfall Waterfall — good warm-up composition before the bigger falls further down.", "log": "Glen Etive Road, Ballachulish PH49 4HZ\nSmall pull-off · Free\nAllow 20 min", "hist": ""}, {"id": "a19f3fa8-887e-4ea9-acd1-1714efdee543", "info": "Back to Clachaig for a proper breakfast. You''ve done Lost Valley and the waterfall — the rest of the day is easy walking and roadside. Rest your legs.", "log": "✅ SIGNAL OK — Clachaig Inn has WiFi\nClachaig Inn · Breakfast included with room\nFood served from morning · Boots Bar open\nAllow 45–60 minutes", "hist": ""}, {"id": "e301c1ac-b6ec-43bf-b41f-da1c20eb7d6f", "info": "Two locations in one walk from the Clachaig car park. Signal Rock is the forested ridge where the signal fire was lit to begin the 1692 Massacre of Glencoe — mossy woodland, birch and oak canopy, dark ancient character. Clachaig Falls on the River Coe is the photography payoff — a wide cascade and tiered gorge falls, intimate and enclosed, completely different from the grand valley shots all day.", "log": "✅ SIGNAL OK — Clachaig Inn has WiFi\nStart: Clachaig Inn car park — walk out the door\nSignal Rock circular trail: ~2km · 30–45 min · flat woodland path\nClachaig Falls: on same route just below bridge near inn\nFree · No permit · Boots recommended — path muddy", "hist": "Popular legend holds that a signal fire was lit on this boulder at 5:00 AM on 13 February 1692 to begin the Glencoe Massacre. The National Trust for Scotland now disputes this: no evidence supports the story. More likely, the rock — whose original Gaelic name Tom a'' Ghrianain means \"Knoll of the Sun\" — served as a traditional gathering place for the MacDonalds, possibly with pre-Christian druidic associations connected to sun worship.\n\nThe nearby Clachaig Inn — dating to the 16th century, with over 365 malt whiskies — displays a sign reading \"No hawkers or Campbells,\" a wry reference to the massacre that still resonates 334 years later. The NTS Visitor Centre features a 10-minute film narrated by Rory McCann, who played The Hound in Game of Thrones — a fitting choice given that George R.R. Martin cited the Glencoe Massacre as a primary inspiration for the Red Wedding.\n\nHagrid''s Hut from the Harry Potter films (Prisoner of Azkaban) was built on slopes above Torren Lochan, very near the Clachaig Inn. The cliffs opposite were used as Hogwarts exterior shots. The Pass of Glencoe and Clachaig Gully were also filming locations for Monty Python and the Holy Grail."}, {"id": "52aabf07-8f07-4fa1-bd79-7125621ead12", "info": "A hidden lochan enclosed by North American woodland — birch, pine and spruce transplanted from Canada in the 1890s by Lord Strathcona for his homesick Canadian wife. Feels nothing like the open Highland valley 500 metres away. Still water, mountain glimpsed through the trees, forest silence. The intimate counterpoint to every grand landscape shot today.", "log": "⚠️ PATCHY — Glencoe village fringe, patchy\nGlencoe Lochan car park — off minor road north of Glencoe village\nFree · 2.3m height limit on car park entrance\n20–30 min loop walk · completely flat · accessible at all hours\n🦟 Midges likely in sheltered woodland — repellent", "hist": "Donald Alexander Smith (1820–1914) rose from a £20-per-year Hudson''s Bay Company apprentice to become one of the wealthiest men in the British Empire. His defining moment came at 9:22 AM on 7 November 1885, when he drove the last spike of the Canadian Pacific Railway at Craigellachie, British Columbia — one of the most iconic photographs in Canadian history. His first swing bent the iron spike so badly it had to be replaced; the bent original was fashioned into decorative pins mounted with 13 diamonds for officials'' wives.\n\nHis wife Isabella Sophia Hardisty was of Indigenous and Scottish heritage. She was privately called \"our lady of the snows\" by English aristocrats who accepted her hospitality. Created 1st Baron Strathcona and Mount Royal in 1897, Smith originally wanted the title \"Lord Glencoe\" — but was advised against it because of the massacre associations. \"Strathcona\" is described as a Gaelic version of Glencoe.\n\nAfter acquiring the Glencoe Estate in 1895, Strathcona created this artificial lochan and surrounded it with North American conifers — Western hemlock, Douglas fir, Sitka spruce, Western red cedar, and even towering redwoods — to ease Isabella''s homesickness for Canada. Despite this extraordinary gesture, Isabella reportedly never fully took to Glencoe and remained homesick. She died in London in November 1913. Donald died just ten weeks later, suggesting a bond that had survived five marriage ceremonies (repeated due to concerns about the legality of each previous one).\n\nPop culture: Donald Smith''s driving of the last spike of the Canadian Pacific Railway was recreated in the 1974 CBC mini-series The National Dream, based on Pierre Berton''s bestselling two-volume history — one of the most watched Canadian television productions ever made. The bent spike from Smith''s first failed swing was later used in Gordon Lightfoot''s concept for his 1967 song \"Canadian Railroad Trilogy,\" one of Canada''s most beloved folk songs, which begins: \"There was a time in this fair land when the railroad did not run.\" Smith himself appears as a character in numerous Canadian historical novels. The Canadian Pacific Railway — whose construction Smith helped finance — became the subject of the acclaimed 2014 documentary The Last Spike. Glencoe''s Canadian woodland is today one of Scotland''s most unusual ecological anomalies: Pacific Coast trees thriving in a Highland glen, their root systems adapted to Himalayan-scale rainfall, blissfully unaware they are 4,000 miles from home."}, {"id": "43c66d53-e1e8-4856-a9eb-160d700f8b3f", "info": "A small loch on the valley floor ringed by the steepest walls in Glencoe — Aonach Eagach to the north, Three Sisters to the south. On a still afternoon both ridges reflect simultaneously. Achnambeith — the white farmhouse at the base of the Three Sisters, visible from the loch shore — is a distinct and equally strong subject. Tiny white cottage dwarfed by mountain walls with a waterfall thread above it. Do not approach the building — it is a private residence. Shoot from the loch shore and valley floor.", "log": "📵 NO SIGNAL — deep in Glencoe pass. Satellite device active.\nPark: A82 layby just west of the loch\nCoords: 56.6720°N, 5.0310°W\nRoadside — 2 min walk to loch shore\nReflection dependent on wind stillness — patience required", "hist": "The small loch''s historical name — Loch Trychardan, \"Loch of the Three Friends\" — likely refers to three MacDonald settlements along its shore, all destroyed in the 1692 massacre. NTS excavations (2018–2024) uncovered remains of the township including houses, barns, and a grain-drying kiln, with evidence that MacDonalds returned after the massacre before being driven out by 19th-century sheep farming. At nearby Achnacon in 2024, archaeologists discovered a bent plaid pin, musket ball fragments, and 17th-century bronze coins — possibly from a gambling session interrupted by the massacre.\n\nAchnambeith Cottage (c.1900) is a private residence. The glen is reputedly haunted. On the anniversary of the massacre, people claim to glimpse ghostly shadows of fugitive clansmen. Most compelling is the legend of Corrag, the Witch of Glencoe, who allegedly foretold the massacre but was ignored. After the killings, she cast MacIain''s broadsword into Loch Leven, saying: \"So long as this sword lays undisturbed by man, no man from this Glen will die by the sword again.\" In June 1916, a dredger raised the sword. The following day — 1 July 1916, the first day of the Battle of the Somme — seven men from Glencoe died, the first from the glen to die in battle since the massacre.\n\nThe Nine of Diamonds playing card is called the \"Curse of Scotland\" — massacre orders were reputedly written on one.\n\nPop culture: Glencoe valley is one of the most filmed landscapes in Scotland. The Starz series Outlander (2014–2023) used Glencoe extensively throughout its eight seasons — the valley''s visual character is inseparable from the show''s Jacobite aesthetic, and the Glencoe Massacre itself features in Season 2. Highlander (1986), starring Christopher Lambert and Sean Connery, filmed key scenes on the Glencoe valley road and the surrounding peaks — the film''s immortal Scottish warrior aesthetic was largely built on this landscape. Rob Roy (1995), with Liam Neeson and Jessica Lange, filmed numerous battle and chase sequences in the glen. The 1692 massacre itself was depicted in the 1971 BBC drama Massacre at Glen Coe and the 2008 National Theatre of Scotland production The Strange Undoing of Prudencia Hart. The valley also appears briefly in Steven Spielberg''s Schindler''s List (1993), in a scene depicting a train journey through Highland Scotland."}, {"id": "ffd1edc0-ac31-485a-bc51-571834f9c95e", "info": "At the western end of the Glencoe valley the mountains open onto the tidal sea loch of Loch Leven. The Pap of Glencoe — a distinctive conical peak — rises above the south shore. Tidal foreground changes through the day. The north shore B863 road offers a hidden bay layby with moored boats and complete quiet. Western sun at this hour sidelights the Pap''s conical form. In B&W the bare rock geology reads as distinct ridgelines and gullies against a near-black sky with red filter — more graphically powerful than snow.", "log": "⚠️ PATCHY — edge of Ballachulish, patchy\nFrom Loch Achtriochtan: 10min west on A82 through Glencoe village\nCross Ballachulish bridge → right onto B863 north shore road\nLayby with stone wall ~1 mile along B863 — gate leads to hidden bay\nAlso shootable from A82 roadside just west of Glencoe village\nFree · Roadside access · Allow 45 min", "hist": "Sgorr na Cìche — \"Peak of the Breast\" — towers 742 metres above Glencoe village. Nearby Sgòrr nam Fiannaidh (\"Peak of the Fingallian Warriors\") is named for Fionn Mac Cumhaill''s warriors, who legendarily charged down the hillside to drive Viking invaders from Loch Leven.\n\nThe Ballachulish Slate Quarry began operations in 1693 — one year after the massacre — when travelling quarriers spotted slate and started digging. By the mid-1800s, annual output reached 26 million slates, and Ballachulish produced more than half of all domestic slates quarried in Scotland. The quarry closed in 1955; blue pools now fill the old workings.\n\nOn 14 May 1752, government factor Colin Roy Campbell of Glenure (\"The Red Fox\") was shot in the back by a concealed marksman. James Stewart of the Glens was arrested despite a solid alibi, tried before a jury of 11 Campbells at Inveraray Castle — presided over by the victim''s brother — and hanged on 8 November 1752. His body, wrapped in chains, was left hanging for over three years as a warning. A 2013 Royal Society of Edinburgh re-examination using forensic ballistics determined Campbell was likely killed by two unknown gunmen, undermining the entire original conviction. Robert Louis Stevenson wove the case into Kidnapped (1886).\n\nPerhaps most extraordinary: in November 1880, builders discovered a nearly life-size carved wooden figure — 145 centimeters tall, carved from alder, with quartzite pebbles for eyes. Radiocarbon dated to 728–524 BC, the Ballachulish Goddess is the oldest human figure found in Scotland — over 2,500 years old. She may represent the Celtic hag goddess Cailleach Bheithir. Railway workers were reportedly reluctant to handle the \"Pagan Idol\" during transport to Edinburgh, where she now resides in the National Museum of Scotland.\n\nPop culture: Robert Louis Stevenson''s Kidnapped (1886) — inspired by the Appin Murder and set partly on Loch Leven — has been adapted for screen at least eight times, including Disney''s Kidnapped (1960) starring Peter Finch, a 1971 version with Michael Caine as Alan Breck Stewart, and a 2005 BBC adaptation. The Ballachulish ferry crossing that features in the novel was replaced by the Ballachulish Bridge in 1975 — the last working vehicle ferry crossing of Loch Leven. Stevenson called the Appin Murder \"the causeless, fruitless, and disastrous crime\" in a letter, yet it gave him one of Scottish literature''s great adventure novels. The broader Glencoe area appears in Mel Gibson''s Braveheart (1995) — several Battle of Stirling sequences were filmed on the valley floor. The Pap of Glencoe''s distinctive profile appears in dozens of Scottish tourism campaigns and was used by VisitScotland as their primary image for the 2009 \"Homecoming Scotland\" campaign marking the 250th anniversary of Robert Burns''s birth."}, {"id": "df51621e-4465-4d20-8b46-73e1045e679e", "info": "Back to Clachaig. Food served until 9pm. Boots Bar has 300+ whiskies. You''ve earned it — Lost Valley, Etive Mor, Signal Rock, Glencoe Lochan, Loch Achtriochtan, Loch Leven. Six stops, one full Highland day.", "log": "✅ SIGNAL OK — Clachaig Inn has WiFi\nClachaig Inn · Food served noon–9pm\nBoots Bar · 300+ malts\nCheck out tomorrow: 8:30–10:30am", "hist": ""}, {"id": "604c50f4-73d2-4d65-8470-28e132ac234c", "info": "Starting location: Clachaig Inn — Glencoe. Drive to first stop: ~5 min.", "log": "", "hist": ""}, {"id": "d2f98e9c-af25-48b8-abb2-f65d8c40334d", "info": "Check out between 8:30–10:30am. Load the car, fuel up at Ballachulish before heading north. Route: A82 north through Fort William, then A87 west toward Kyle of Lochalsh and the Skye bridge.", "log": "✅ SIGNAL OK — Clachaig Inn has WiFi\nClachaig Inn, Glencoe PH49 4HX\nCheck-out: 8:30–10:30am\nFuel: Ballachulish petrol station before heading north\nRoute: A82 north → Fort William → A87 west → Kyle of Lochalsh → Skye Bridge → A87/A850 to Sligachan → A855 to Staffin\nTotal drive: ~3hrs 30min without stops", "hist": ""}, {"id": "2f6df605-5a5a-4009-8670-bd9085e30091", "info": "Roadside pull-off directly below the Five Sisters on the A87. The full ridge rises steeply above you — dramatic close-up angle shooting upward at the five distinct peaks. Park at the Glen Shiel car park (free) and shoot from the road. Battle of Glen Shiel information board on site.", "log": "A87, Kyle IV40 8HU\nGlen Shiel Car Park · Free\nAllow 20 min", "hist": ""}, {"id": "f15e53a3-b5a4-48f7-9543-005249e2b71b", "info": "The definitive Five Sisters postcard shot. A short detour off the A87 at Shiel Bridge up a single-track road to a car park at the Bealach Ratagan. All five peaks lined up across Loch Duich — the full ridge reflected in the water with distance and scale impossible to achieve from the valley floor.", "log": "Detour: turn south at Shiel Bridge off A87\nSingle track road · Car park 3/4 up the pass · Free\nAllow 30 min including drive", "hist": ""}, {"id": "b9cd1c1b-c43b-4638-82f0-86c88b9b9850", "info": "Scotland''s most photographed castle on a small tidal island where three sea lochs meet — Loch Duich, Loch Long, and Loch Alsh. The three-arched bridge connects the island to the shore. Arriving around 1pm gives good midday light on the castle face. Three shooting positions: front rocky shore with castle centered, low angle on the seaweed and tidal rock, and the bridge-led reflection from the east bank. Also turn 180 degrees — looking east down Loch Duich with the Five Sisters visible in the far distance is a distinct and equally strong composition.", "log": "✅ SIGNAL OK — Dornie village, reasonable coverage\nA87 road through Dornie village · Right on the road, signed\nFree parking on both sides of the road\nAllow 45–60 min · Tide dependent for foreground\nDistance from Glen Shiel: ~25min", "hist": "Originally a 13th-century fortification built by Alexander III of Scotland to defend against Viking raids. The MacRae clan — hereditary constables — called themselves ''MacKenzie''s shirt of mail'' because they so often stood between their chiefs and enemy blades in battle. In 1719 the castle was garrisoned by 40 Spanish soldiers as the Jacobite supply base — the same rising fought at Glen Shiel an hour''s drive east. A British naval squadron entered Loch Alsh on 10 May, bombarded the castle with three frigates for several hours, then blew it up with 27 barrels of gunpowder. It lay in complete ruin for nearly 200 years.\n\nLt Colonel John MacRae-Gilstrap began rebuilding in 1912, guided in part by a dream his wife had about the castle''s original interior layout. Reconstruction took 20 years and £250,000 — equivalent to over £15 million today. 200,000 tons of material were moved.\n\nIt is now the most photographed castle in Scotland and one of the most filmed in the world. Pop culture appearances: Highlander (1986) with Christopher Lambert and Sean Connery, The World Is Not Enough (1999) with Pierce Brosnan as James Bond, Elizabeth: The Golden Age (2007) with Cate Blanchett, Brave (2012) by Pixar/Disney, and dozens of commercials and album covers. It appears on more Scottish shortbread tins than any other image in existence. The castle was voted Scotland''s most popular landmark in a 2011 poll."}, {"id": "1ed13f47-4d27-482a-aef3-0a68370d7b66", "info": "The Skye Bridge opened in 1995, replacing the last working vehicle ferry. When it opened it was the longest concrete bridge in Scotland. Toll was abolished in 2004 after years of protest — campaigners, inspired by the ancient Scottish tradition of free passage, refused to pay and accepted fines instead. The first mainland-to-Skye fixed link in history.", "log": "✅ SIGNAL OK — Kyle of Lochalsh, good coverage\nA87 · No toll · Open 24hrs\nKyle of Lochalsh → Kyleakin, Skye\nDistance from Eilean Donan: ~20min", "hist": ""}, {"id": "547a6ba0-8f65-44b8-b8d1-77837cf7d927", "info": "18th century three-arched stone bridge at the crossroads of Skye. The Black Cuillin Ridge rises directly behind it — 11 Munros, the most technically demanding mountain ridge in Britain. The river runs peat-dark from the moorland above. Three distinct shooting positions covering the front-on arch composition, low long-exposure river foreground, and the side angle through the arches.", "log": "⚠️ PATCHY — hotel has WiFi, outdoor signal unreliable\nA87/A863 junction, Sligachan · Large free car park at Sligachan Hotel\nCamera in the river — wellies essential\nAllow 30–40 minutes\nOor Neuk: ~25min north on A87/A855", "hist": "The Sligachan Hotel beside the bridge opened in 1830 and became the base for the first serious attempts to climb the Black Cuillin — the most technically demanding mountain ridge in Britain. Norman Collie, one of the great Victorian alpinists who made first ascents in the Himalayas and Canadian Rockies, spent 40 summers at Sligachan. After his death in 1942 he was buried here as he requested — his ghost is said to wander the glen on winter nights.\n\nThe fairy legend: washing your face in the river water here grants eternal youth and beauty — provided you submerge your face for seven seconds without breathing. Local tradition held this was how the fairy folk maintained their ageless appearance.\n\nThe name Sligachan means ''place of shells'' in Gaelic. The crossroads here is the geographic heart of Skye — every road on the island eventually passes through it. Outlander used the surrounding glen extensively. The Cuillin Ridge rising above the bridge was described by mountaineer W.H. Murray as ''the only genuine mountaineering country in Britain'' — it remains unclimbed by many experienced alpinists."}, {"id": "0816f48e-a6f3-4f92-b93c-3efc1c95d651", "info": "Whole house rental near Tole, Staffin, on the northeast coast of Skye. Base for three nights. Check in from 4pm. Unload, settle in, early dinner. Tomorrow is a 4am alarm for the Old Man of Storr sunrise.", "log": "Oor Neuk, Tole, Staffin, Isle of Skye\nCheck-in: from 4:00pm · Check-out: 10:00am Jul 3\n3 nights · Whole house\n⚠️ Load film holders tonight\n⚠️ Set THREE alarms: 3:30am wake · Out by 3:50am · Old Man car park 4:05am · Sunrise 4:28am", "hist": ""}, {"id": "b1ba6b8f-0672-4ddd-8937-330778c974de", "info": "Jurassic-era dinosaur footprints preserved in the tidal rock platform at Staffin — one of the few accessible dinosaur trackways in Scotland. Best viewed at low tide. Look for sauropod and theropod prints in the layered limestone slabs near the harbour. Staffin Dinosaur Museum nearby if open.", "log": "Staffin Harbour Car Park · Free\n57.63313°N, 6.19815°W\nCheck tide tables for Jun 28 — best at low or mid tide\nAllow 1 hour", "hist": ""}, {"id": "f3e45a58-c3cc-45fd-ad71-55fbfaa73693", "info": "Starting location: Oor Neuk — Tole, Staffin. Drive to first stop: ~21 min.", "log": "", "hist": ""}, {"id": "9ac331e7-7f1c-4b3f-a9ed-617a2159e0a5", "info": "The most iconic photography location on Skye. A 55-metre basalt pinnacle rising from a massive ancient landslip on the Trotternish Ridge. Three shooting positions: elevated northwest viewpoint above the pinnacles (requires extra 15–20 min beyond the main path), close position among the pinnacles looking up, and the standard path viewpoint with the Sound of Raasay stretching left. The June green grass separates beautifully from the dark basalt with red filter.", "log": "⚠️ PATCHY — Trotternish, weak signal. Download offline.\nA855 Storr car park · Free · Large car park fills by 9am in peak season\nDepart Oor Neuk 7:30am · Car park 7:45am · Shooting 8:25–10:00am\n40 min uphill on well-maintained steep path · No scrambling\n4x5 kit in padded backpack · Allow 90 min on hill", "hist": "The 55-metre pinnacle formed from a massive landslip 10,000–15,000 years ago when retreating glaciers destabilized the thick basalt above weaker Jurassic sedimentary rock — the entire slope is still slowly moving. The Old Man was first climbed in 1955 by Don Whillans — the rock is so unstable it has been repeated only a handful of times since, described as ''climbing lumps of coal.'' In Old Norse, Storr means ''Great Man.'' The pinnacle was used as a navigation marker by Viking seafarers. Legend holds it is the exposed thumb of a giant buried in the ridge, waiting to rise again. The Norse also left place names all across this peninsula — Trotternish itself is from Old Norse Þróndarnes. Ridley Scott''s Prometheus (2012) filmed landscape scenes in the Storr area. The formation also appears in Snow White and the Huntsman (2012), Macbeth (2015 with Michael Fassbender), and The BFG (2016)."}, {"id": "3464ac9b-8e9a-43e1-b5f2-1cc0db94e58a", "info": "Hidden coastal headland 1.5 miles south of Kilt Rock. Dramatically less crowded than any other Trotternish stop. Clifftop views north and south along the coast with sea stacks and crashing Atlantic. Coastal B&W work — cliff edges, breaking waves, headland geometry. Short 20-min walk from road.", "log": "Roadside layby · IV51 · Free · Limited spaces\nWalk through sheep fields · Close gates\nWear waders/grip studs — can be boggy", "hist": ""}, {"id": "1a5c3f96-a687-4b81-a6c8-6f9fe631acfe", "info": "Roadside viewpoint platform on the A855 overlooking 90-metre columnar basalt sea cliffs whose vertical columns resemble kilt pleats, with Mealt Falls dropping 55–60 metres directly into the sea alongside. Both visible from the same platform. Photos to be added.", "log": "⚠️ PATCHY — Trotternish coast, patchy\nA855 north of Staffin · Free car park at viewpoint\nRoadside — no walk required · Allow 20–30 min", "hist": "The upper portion of Kilt Rock is a dolerite sill — magma that intruded along bedding planes of Jurassic sedimentary rocks approximately 60 million years ago, then cooled slowly into vertical columnar joints that resemble the pleats of a kilt. The horizontal layering of differently coloured rock creates a tartan-like pattern. Mealt Falls drops from Loch Mealt directly into the sea — on very windy days the waterfall is blown upward and never reaches the water below. The nearby coast at Rubha nam Brathairean has yielded 165-million-year-old theropod and sauropod tracks. Staffin village is Scotland''s ''Dinosaur Isle.'' The safety fencing at the viewpoint creates an eerie organ-like sound in strong wind as air passes through holes in the piping."}, {"id": "b6ca447e-a5af-47f0-a564-0396a8395531", "info": "Westernmost point of Skye. The lighthouse sits at the end of a dramatic headland with basalt cliff faces and a 20-minute walk from the car park down to the point. Evening shoot — the lighthouse faces west into the Atlantic. On clear days the Outer Hebrides are visible across The Minch. Photos to be added.", "log": "📵 NO SIGNAL — westernmost tip of Skye. Satellite device active. Download offline.\nEnd of B884 road, Glendale · Free car park\n20 min walk down to lighthouse · Allow 2 hours\n~1hr drive from Quiraing", "hist": "Neist Point Lighthouse was first lit on 1 November 1909, designed by David Alan Stevenson — Robert Louis Stevenson''s first cousin, from the famous lighthouse-building dynasty that constructed over 150 Scottish lighthouses across four generations. Automated in 1990. The steamer Doris grounded near the point in 1909, the very year the lighthouse was commissioned. The basalt cliffs display columnar formations connected geologically to the Giant''s Causeway in Northern Ireland. The legend of the Blue Men of the Minch — supernatural sea-dwellers who test ship captains with poetry challenges and seize boats from those who cannot complete the rhyme. Ale was traditionally poured into the sea as a peace offering. The waters below are among Skye''s best for minke whales, porpoises, dolphins, and occasionally orcas. Film: Lars von Trier''s Breaking the Waves (1996), 47 Ronin (2013)."}, {"id": "1b1e83a2-bd9d-43e9-87d4-e7e94a759e3f", "info": "Return to Oor Neuk. ~1hr drive from Neist Point. Load film holders for Day 11.", "log": "B884 back to A863 → A87 → A850 → A855 to Staffin\n~1hr drive · Load film holders tonight\nDay 11 depart 8:00am — Fairy Pools, Talisker Bay, Elgol", "hist": ""}, {"id": "4547d351-66fc-47fb-857d-01d380ecf4e7", "info": "Starting location: Oor Neuk — Tole, Staffin, Isle of Skye. Drive to first stop: ~37 min.", "log": "", "hist": ""}, {"id": "ca1059eb-f2f7-4523-abec-67ff31e23eed", "info": "The most dramatic landscape on Skye — ancient landslip has created a labyrinth of pinnacles, cliffs and hidden plateaux on the Trotternish Ridge. The Circuit passes the Prison, Needle and Table formations before climbing the ridge for sweeping coastal views. Go counter-clockwise: steep stone steps first, ridge descent second.", "log": "Quiraing Car Park · IV51 · £3 up to 3hrs / £5 up to 6hrs\nCard or coins · Do NOT park on verges (soft peat — you will get stuck)", "hist": ""}, {"id": "b2cba484-dae4-407a-a0bd-8c94f04b83f6", "info": "Crystal clear pools and cascades fed by meltwater off the Black Cuillin gabbro and peridotite — some of the oldest exposed rock in Britain. The water is extraordinarily clear because the igneous rock contains almost no soluble minerals. Three shooting positions: the main wide cascade looking upstream toward the ridge (Shot 1), a turbulent boulder rapid above the pools (Shot 2), and the natural underwater arch connecting two pools (Shot 3, calm water only). At 7am the path is yours — crowds arrive by 10am. Tripod feet go in the stream — mid-calf waterproof boots required.", "log": "⚠️ PATCHY — Glen Brittle, unreliable. Download offline.\nCar park on B8009, Glenbrittle · £8 per vehicle (community-run)\nWalk: 2.4km each way · 20 min to first pools · Well-maintained gravel path\nArrive car park 7:00am · First pools 7:20am · Shoot 7:20–9:30am · Back to car 10:00am\n🥾 Mid-calf waterproof boots required — tripod feet in stream\n☂️ Tripod-mountable umbrella", "hist": "The name ''Fairy Pools'' is a 1930s marketing invention — coined by a tour guide, first appearing in a guidebook. Before that, the location was known solely as Coire na Creiche: ''corrie of the spoils.''\n\nThe spoils refer to the Battle of Coire na Creiche, 1601 — fought right here. Known as the Wars of the One-Eyed Woman: the MacLeod of Dunvegan offered his sister Margaret in a trial marriage to the MacDonald of Sleat. When she failed to become pregnant within the year she was returned to her brother tied to a horse, led by a one-eyed servant with a one-eyed dog — a calculated humiliation designed to start a war. It worked. The MacDonalds won but the slaughter was so extreme the pools are said to have run red with blood. King James VI personally intervened and ended the feud. Last clan battle on Skye.\n\nThe selkie legend is also attached to Glenbrittle: shape-shifting seal-people who shed their skins at the beach and bathed in the pools under a full moon. Unlike the fairy name, the selkie association is genuine older folklore.\n\nThe water clarity comes from the gabbro and peridotite of the Black Cuillin — approximately 60 million years old, containing almost no soluble minerals. The water is essentially distilled by altitude and rapid descent."}, {"id": "d7c5f488-e71f-4696-a15b-0e4209478d88", "info": "Remote beach enclosed by two cliff headlands. North end: near-vertical 100-metre cliff with a waterfall that drops onto the beach and, in a westerly gale, reverses entirely — driven back up the cliff face in sheets. South end: a large sea stack accessible by scrambling at low tide. The beach is a mixture of black volcanic sand and lighter grey grains mottled by burns into marbled patterns that change with every tide. Three compositionally distinct shots from three positions on the same beach.", "log": "📵 NO SIGNAL — remote west Skye coast. Satellite device active.\nPark at road end near Talisker village (NOT Talisker Distillery — that''s Carbost, 3 min away)\nNo formal car park · Roadside only · ~10 cars max · Arrive by 11am\nWalk: 1.7km on good gravel path · ~20 min · Flat · Some muddy sections\nNo facilities on beach — bring water and food\nTide tables: aim within 2 hours of low tide for full sand and stack access\n🥾 Mid-calf waterproof boots · ☂️ Tripod-mountable umbrella\nAllow 2 hours on beach · Depart ~1:30pm\nTalisker Distillery 3 min away in Carbost · Open from 10am if time allows", "hist": "Hugh MacAskill took ownership of Talisker Estate in 1825. His first act was to clear the tenants — families evicted for sheep farming, many emigrating to Nova Scotia and Cape Breton Island. That same cleared land grew the barley for Talisker Distillery, co-founded with his brother Kenneth in 1830. The distillery was built on the proceeds of the Clearances. It burned down in 1960 and was rebuilt the same year.\n\nRobert Louis Stevenson praised Talisker in his poem ''The Scotsman''s Return from Abroad,'' calling it among the kings of drinks. The line appears on Talisker bottles to this day. His father Thomas Stevenson — the great lighthouse engineer — built the lighthouse at Rubha nan Clach, just visible around the northern headland. Father built the lighthouse; son praised the whisky.\n\nTalisker House — the white manor on the path to the beach, built in the 1720s — was for centuries the residence of the heir to Clan MacLeod chief. Sold in 2019 for £1.2 million.\n\nThe waterfall reversal — water driven back up the cliff by Atlantic westerlies — is the same physics as the Mealt Falls at Kilt Rock. Both are globally rare."}, {"id": "191f2cde-30b1-4536-acf7-67ff8cb24715", "info": "James tee time at Isle of Skye Golf Course. 18 holes, 7:00 PM. Ref: BMEG2-XUYQ1-969 · £40 green fee · With Jack Cyr.", "log": "Isle of Skye Golf Course · Sconser, Isle of Skye IV48 8TD\nTee time: 19:00 · 18 holes\nRef: BMEG2-XUYQ1-969 · Paid £80 total", "hist": ""}, {"id": "f6f82bfb-372e-4a64-94aa-81a3dd5a1415", "info": "The finest sea-level panorama of the Black Cuillin Ridge in existence. From Elgol you look northwest across Loch Scavaig directly inside the Cuillin horseshoe. The foreground geology spans 170-million-year-old Jurassic sandstone cut by 60-million-year-old basaltic dykes — 110 million years of geological time readable in a single boulder field. Three shots across the afternoon and evening: full panorama on arrival (~4pm), wave surge on the flat sandstone shelf (~5–7pm), yellow honeycomb sandstone overhang against Blà Bheinn in low sun (~8–9pm).", "log": "📵 NO SIGNAL — very remote south Skye. Satellite device active. Download offline.\nFree car park at harbour · Elgol IV49 9BJ\nWalk to beach: 5 min from car park to rocks north of pier\nB8083 from Broadford · 14 miles single track · Allow 40 min\nTide tables critical — foreground shelf access changes with tide\nArrive 4:00pm · Shot 1 ~4pm · Shot 2 ~5–7pm · Shot 3 ~8–9pm\nLeave by 9:00pm · B8083 → A87 north → A855 north ~1hr 20min\n🥾 Mid-calf waterproof boots essential for shelf · ☂️ Tripod-mountable umbrella\nCuillin View Coffee Shop in upper Elgol — open on arrival if needed", "hist": "Bonnie Prince Charlie sheltered at Elgol on 4 July 1746 — ten weeks after Culloden. The Clan MacKinnon hid him here at considerable personal risk. He sailed overnight from Elgol harbour to Mallaig on the mainland, spending a further ten weeks in hiding before escaping to France. A cave on the headland south of the village — accessible only two hours either side of low tide — is known as Bonnie Prince Charlie''s Cave.\n\nJMW Turner came to Loch Coruisk — accessible by boat from Elgol jetty — in 1831, the year after Sir Walter Scott published Lord of the Isles romanticising the Cuillin. Turner''s painting became one of the most celebrated British landscape paintings of the 19th century. Tennyson visited the same loch and saw nothing but thick white fog.\n\nSir Walter Scott visited Loch Coruisk in 1814 and set part of The Lord of the Isles (1815) there, describing the Cuillin as the most savage landscape in Britain. The publication triggered the Victorian tourist boom that invented the Highland landscape as a destination.\n\nThe foreground geology spans two eras: Jurassic sandstone 170 million years old — remnants of a warm shallow sea — cut by basaltic dykes from the Cuillin volcanic episode 60 million years ago. 110 million years of geological time in a single boulder field at eye level.\n\nWhite-tailed eagles — the largest bird of prey in Britain, reintroduced to Skye in the 1970s from Norway — hunt Loch Scavaig regularly. Seals haul out on the loch rocks. Basking sharks and dolphins reported offshore in summer."}, {"id": "99bcb630-3f9b-4312-aa85-36308ea6550d", "info": "Return drive from Elgol to Oor Neuk. Last night at Oor Neuk — check-out July 3.", "log": "🚗 B8083 east → A87 north → A855 north to Staffin\n~1hr 20min drive · Arrive ~10:30–11pm\nBag exposed film holders · Note emulsion numbers\n⚠️ Last night at Oor Neuk · Check-out July 3", "hist": ""}, {"id": "dc15b73d-3468-4cb1-b92d-acd1050a6ab4", "info": "Starting location: Oor Neuk — Tole, Staffin, Isle of Skye. Drive to first stop: ~5 min.", "log": "", "hist": ""}, {"id": "954d6b81-1358-435c-99c9-697945e23bfe", "info": "Check out by 10:00am. Load up, begin the long drive south.", "log": "Oor Neuk, Tole, Staffin IV51 9PG · Conf: 6926.868.123\nPhone: +44 7810 237996 · Check-out: 10:00", "hist": ""}, {"id": "6ca166e1-062b-4f60-96a8-ac2192ed403d", "info": "26-metre fishing vessel beached on Loch Linnhe in a 2011 storm. Rusting hull with Ben Nevis as backdrop.", "log": "Corpach Basin · PH33 7JH · Free parking\n10-15 min walk: canal path to footbridge to beach\nBest shot: cross the stream for hull and Ben Nevis in same frame\nCheck tide - low tide reveals more hull", "hist": ""}, {"id": "266d4b10-bf5b-4565-8dbf-95d00c9942a2", "info": "The Home of Golf — a full afternoon covering lunch, the Old Course, shopping and the Cathedral ruins. All stops are walkable from Links Car Park (free).", "log": "SCHEDULE:\n3:15 PM - Lunch: Mitchells Deli or Forgans, Market Street\n4:15 PM - Swilcan Bridge photos (18th fairway, Old Course) 45 min\n5:00 PM - R&A Golf Shop (next to clubhouse) 30 min\n5:30 PM - St Andrews Links Trust Golf Shop 30 min\n6:00 PM - Himalayas Putting Course (18 holes, book online) 45 min\n6:45 PM - St Andrews Cathedral ruins + Castle 30 min\n7:15 PM - Drive to Edinburgh 1.5 hrs\n\nParking: Links Car Park free - all stops within 15 min walk\nHimalayas: Book 18-hole Blue course online - 3-5 GBP per person\nCathedral: Free grounds, small fee for tower climb", "hist": ""}, {"id": "de1afc62-a07f-4f93-b34c-8865e12e63f9", "info": "Starting location: Fraser Suites Edinburgh — St Giles St. Drive to first stop: ~12 min.", "log": "", "hist": ""}, {"id": "230458be-4b18-4964-bab2-056acdef4429", "info": "Pre-booked guided tour. 3 tickets, order #20260311-222308071. Arrive by 9:30am to check in with guide at Tour Meeting Point (just through Main Gate, to the right). Radio earpiece provided. Tour runs 9:45–10:15am. Allow extra time after to explore independently.", "log": "✅ SIGNAL OK — Edinburgh city centre\nEdinburgh Castle, Castlehill EH1 2NG\nOrder: #20260311-222308071 · eTickets on mobile\nGuided Tour 9:45–10:15am · £30/person · 3 adults = £90", "hist": "Edinburgh Castle: 900 years of siege, coronation, and supernatural event.\n\nThe castle sits on Castle Rock — the plug of an ancient volcano that last erupted approximately 350 million years ago. The rock rises 130 metres above the surrounding plain and was inhabited as early as 900 BC by an Iron Age community. The oldest surviving building is St Margaret''s Chapel, built around 1130 by King David I in memory of his mother, Queen Margaret — it is the oldest building in Edinburgh and has been in continuous religious use ever since.\n\nMary Queen of Scots gave birth to the future James VI of Scotland (and James I of England) here in June 1566 — in a tiny closet room barely large enough for a bed, chosen deliberately because its single window allowed witnesses to see there was no possibility of substituting a different infant. The Scottish Crown Jewels — the Honours of Scotland, the oldest crown jewels in Britain, predating the English Crown Jewels by over a century — were hidden in a locked chest after the Act of Union in 1707 and forgotten for 111 years. In 1818, Sir Walter Scott obtained royal permission to search the castle for them. He found them in a dusty chest exactly where they had been left. During WWII, the Crown of Scotland was hidden in a medieval latrine (toilet) in David''s Tower.\n\nThe Stone of Destiny, seized by Edward I of England in 1296 and built into the Coronation Chair at Westminster Abbey, was used for every English and British coronation until 1953. In 1950, four Scottish students broke into Westminster Abbey on Christmas Day and stole the Stone — it broke in two during removal. Three months later it was found at Arbroath Abbey, wrapped in a Scottish flag. Many historians believe the original Stone may never have been taken — that the monks of Scone gave Edward I a plain block of sandstone while hiding the real Stone. The castle''s most persistent legend involves the Piper Boy — a boy sent to explore newly discovered tunnels, whose bagpipes could be heard moving along the Royal Mile until, near the Tron Kirk, the music stopped. He was never seen again."}, {"id": "8ca988db-d6ac-4e32-b26c-f4b6b3686d6a", "info": "Exterior photography circuit of Edinburgh Castle. All within 15 min walk of the castle gate.", "log": "CIRCUIT:\nPrinces Street Gardens — south-facing view of castle on the rock (classic angle)\nThe Vennel Steps — framed castle view between buildings with lamppost (Grassmarket)\nGrassmarket — castle looming overhead\nPrinces Street — long axis shot with Scott Monument\n\nAll free · No entry required · Morning light hits south face well", "hist": ""}, {"id": "8b84bd24-5fc1-4a9c-a5a0-5effdf4ed15b", "info": "The Royal Mile, Grassmarket, Victoria Street (said to inspire Diagon Alley). Walk off the golf.", "log": "Victoria Street: Edinburgh EH1 2JW · Grassmarket: Edinburgh EH1 2JR", "hist": "Dean Village and the Old Town: 800 years in a hidden gorge.\n\nDean Village has existed as a separate community for over 800 years, sitting 30 metres below the rest of Edinburgh in the gorge of the Water of Leith. It was the center of Edinburgh''s grain milling industry from at least the 12th century — at peak operation, 11 watermills ran continuously along this short stretch of river, grinding grain for the entire city. The Incorporation of Baxters (bakers) Guild administered the mills under a charter dating to 1584. By the 19th century the mills had closed and Dean Village became a notorious slum. Rescued in the 1970s–80s by architectural conservation, it is now one of the most photographed areas of the city — completely invisible from the streets above.\n\nThe Royal Mile runs from the Castle to Holyrood Palace — one of the most historically dense streets in Europe. John Knox, the Protestant reformer whose confrontations with Mary Queen of Scots helped shape Scotland''s religious identity, lived on the Royal Mile. The Real Mary King''s Close is an entire 17th-century street buried under later construction — residents were not evicted during the plague as legend claims, but the street was roofed over and built upon. Deacon Brodie — a respectable Edinburgh cabinet-maker by day and burglar by night — inspired Robert Louis Stevenson''s Dr Jekyll and Mr Hyde. He was hanged in 1788 on a gallows he himself had designed in a previous contract.\n\nThe Vennel is a close off the Grassmarket offering the finest framed view of Edinburgh Castle in the city — the entire castle profile appears through a gap in the old Flodden Wall, which was built in panic after the Scottish defeat at Flodden Field (1513). The Grassmarket itself was Edinburgh''s primary place of public execution — approximately 100 people hanged here between 1660 and 1784. The most remarkable execution: Maggie Dickson (1724), hanged for concealing the death of an illegitimate child, placed in a coffin, carted away — and then heard hammering from inside. The noose had failed to break her neck. Scottish law held a sentence, once carried out, could not be repeated. She was freed, lived another 40 years, and is commemorated by a pub near the Grassmarket today."}, {"id": "02e3ebd4-b9d5-499c-9359-5b776e417d9d", "info": "Extinct volcano, 251m above Edinburgh. 360° views of the city, Firth of Forth, Pentland Hills and Highlands. Via Nether Hill Circular — 1.6 mi loop, 1–1.5 hrs, moderate.", "log": "Holyrood Car Park · 55.951133,-3.169840 · Free\nAllTrails: Nether Hill Circular · 1.6 mi · 501 ft elevation · 1–1.5 hrs\nRoute: stone steps up Volunteer''s Walk → Nether Hill → rocky summit → Piper''s Walk descent\nRocky summit — good grip footwear essential · Can be slippery", "hist": ""}, {"id": "9c2e9251-eabe-4433-bbae-49ff2c4fbfab", "info": "The most famous photography viewpoint in Edinburgh. Nelson Monument and National Monument (Parthenon columns) with the castle below.", "log": "✅ SIGNAL OK — Edinburgh city centre\nAccess from Regent Road, Edinburgh · Free · Always open\n10 min walk from Princes Street", "hist": "Greyfriars Kirkyard: J.K. Rowling''s graveyard, Greyfriars Bobby, and the world''s most violent poltergeist.\n\nThe kirkyard opened in 1562 and contains some of the most elaborate 17th-century funerary monuments in Scotland. It was also the site of the signing of the National Covenant (1638), when tens of thousands of Scots signed a document rejecting Charles I''s attempts to impose bishops on the Presbyterian church — an act of religious defiance that led to decades of civil war.\n\nThe most famous resident is Greyfriars Bobby — a Skye Terrier who, after his owner John Gray died in 1858, guarded the grave for 14 years until his own death in 1872. The Lord Provost of Edinburgh gave him a special licence so he could live in the city without an owner. His water bowl was replaced daily. A statue was erected in 1873; rubbing Bobby''s nose is believed to bring good luck, and the bronze nose has been polished bright by millions of hands. The City of Edinburgh has twice had to replace the nose after it was rubbed completely smooth.\n\nJ.K. Rowling spent years writing in the nearby Elephant House café and the Spoon café with a view of the castle. Greyfriars Kirkyard contains the graves of Thomas Riddell (died 1806), William McGonagall (the famously terrible poet), Professor John Murray, John Gray (Bobby''s owner), and others whose names she transferred to Harry Potter characters. Tom Riddle became Lord Voldemort; McGonagall became Professor McGonagall. The graveyard is now a pilgrimage site for Harry Potter fans from around the world.\n\nThe Mackenzie Poltergeist is considered the best-documented supernatural case in the world. Sir George \"Bluidy\" Mackenzie imprisoned 1,200 Covenanters in a walled field next to the kirkyard in 1679 — many died of exposure. In 1999, a homeless man broke into Mackenzie''s mausoleum seeking shelter and accidentally fell into an old plague pit. From that point, visitors began reporting scratches, bruises, burns, bites — inexplicable physical attacks occurring under their clothing. Over 500 documented cases have been recorded. Two exorcisms were attempted; both exorcists collapsed. The tours specifically warn visitors: \"The Mackenzie Poltergeist can cause genuine physical and mental distress. Participate at your own risk.\""}, {"id": "3aee45a4-bc99-4ffa-ba93-eb50dcd794ac", "info": "17th century graveyard. Famous for Greyfriars Bobby, elaborate carved memorials, and the Covenanters'' Prison.", "log": "✅ SIGNAL OK — Edinburgh city centre\nGreyfriars Place, Edinburgh EH1 2QQ · Free · Always open", "hist": "Dean Village: a hidden medieval milling community in the heart of a capital city.\n\nDean Village has existed as a separate community for over 800 years, sitting 30 metres below the rest of Edinburgh in the gorge of the Water of Leith. It was the center of Edinburgh''s grain milling industry from at least the 12th century — at peak operation, 11 watermills ran continuously along this short stretch of river, grinding grain for the entire city. The Incorporation of Baxters (bakers) Guild administered the mills under a charter dating to 1584, controlling grain prices and quality for the city above.\n\nBy the 19th century the mills had closed, replaced by industrial technology, and Dean Village became a notorious slum. It was rescued in the 1970s and 1980s by architectural conservation, and is now one of the most photographed areas of the city — completely invisible from the streets above, quiet even in high tourist season.\n\nThe Water of Leith walkway runs 12 miles from the Pentland Hills through the village and down to Leith on the Firth of Forth. Robert Louis Stevenson walked this route regularly as a student. Edinburgh''s only surviving Roman fort is visible on the riverbank a mile upstream at Cramond, where the Water of Almond meets the Firth of Forth."}, {"id": "6fc1ebf2-b362-449f-a977-84f30e77f322", "info": "Starting location: Fraser Suites Edinburgh — St Giles St. Drive to first stop: ~5 min.", "log": "", "hist": ""}, {"id": "34e91714-abfb-4610-924c-e5bcb994f050", "info": "⚠️ Very early start. Airport is 30–45 min from hotel. FR809 departs 07:55. Arrange luggage collection the night before if possible.", "log": "Fraser Suites: +44 131 221 7200 · Conf: 52611SG109917\nTaxi to EDI: ~£25–30 / 30 min", "hist": ""}, {"id": "d43251f7-e3e5-4770-95b1-90c395159bd5", "info": "Ryanair. Land Dublin 09:00. 3.5 hour connection to EI 117.", "log": "Flight: FR809 · Ryanair\nDeparts: 07:55 EDI · Arrives: 09:00 DUB\nConf: U72I6U", "hist": ""}, {"id": "c5d03291-e6b9-4b07-9f48-1f8e09ec4838", "info": "International to international connection. Clear through the terminal. Airside food and shops while waiting.", "log": "Dublin Airport · Terminal 1 → Terminal 2\nEI 117 departs 12:35", "hist": ""}, {"id": "87be1827-e0be-44d1-9ef4-177443744fe3", "info": "Final leg home. Arrives Washington Dulles 15:45. Get film holders organised — first thing after landing: ship everything to Praus Productions.", "log": "Flight: EI 117 · Aer Lingus\nDeparts: 12:35 DUB · Arrives: 15:45 IAD\nConf: 2JWMSW\n\n── Post-trip ──\nPraus Productions · Rochester NY\n4x5 development: $3.50/sheet · D-76 1:1\nScanning: ~$45 tier · 1300ppi · 68MB files", "hist": ""}];

async function updateStop(stop) {
  return new Promise((resolve, reject) => {
    const data = JSON.stringify({ info: stop.info, log: stop.log, hist: stop.hist });
    const path = `/rest/v1/stops?id=eq.${stop.id}`;
    const options = {
      hostname: SUPABASE_URL,
      path,
      method: 'PATCH',
      headers: {
        'apikey': SERVICE_KEY,
        'Authorization': `Bearer ${SERVICE_KEY}`,
        'Content-Type': 'application/json',
        'Prefer': 'return=minimal',
        'Content-Length': Buffer.byteLength(data)
      }
    };
    const req = https.request(options, (res) => {
      res.on('data', () => {});
      res.on('end', () => resolve(res.statusCode));
    });
    req.on('error', reject);
    req.write(data);
    req.end();
  });
}

async function main() {
  let success = 0, failed = 0;
  for (let i = 0; i < updates.length; i++) {
    try {
      const status = await updateStop(updates[i]);
      if (status >= 200 && status < 300) {
        success++;
        if (success % 10 === 0) console.log(`Updated ${success}/${updates.length} stops...`);
      } else {
        failed++;
        console.log(`Failed stop ${updates[i].id}: status ${status}`);
      }
    } catch(e) {
      failed++;
      console.log(`Error stop ${i}:`, e.message);
    }
  }
  console.log(`\nDone! Success: ${success}, Failed: ${failed}`);
}

main();
